{
  "name": "星愿·夜穹 (Star Wish Night Sky)",
  "description": "An immersive, interactive firework experience featuring physics-based particle systems, generative audio, and poetic blessings under a shifting aurora sky.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Point {
  x: number;
  y: number;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  maxLife: number;
  color: string;
  size: number;
  friction: number;
  gravity: number;
  trail: Point[];
  shape?: 'star' | 'circle' | 'heart';
}

export interface FireworkProjectile {
  x: number;
  y: number;
  targetY: number;
  vx: number;
  vy: number;
  color: string;
  power: number;
  trail: Point[];
  active: boolean;
}

export interface Blessing {
  text: string;
  opacity: number;
  y: number;
  id: number;
}

class AudioService {
  private ctx: AudioContext | null = null;
  private comboCount: number = 0;

  private init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume();
    }
  }

  playLaunch() {
    this.init();
    if (!this.ctx) return;

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(1200, this.ctx.currentTime + 0.3);

    gain.gain.setValueAtTime(0.1, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }

  playPop(power: number) {
    this.init();
    if (!this.ctx) return;

    const noise = this.ctx.createBufferSource();
    const bufferSize = this.ctx.sampleRate * 0.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);

    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(power > 1 ? 2000 : 800, this.ctx.currentTime);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.3 * (power/2), this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);

    noise.start();

    // Occasional bell chime
    if (Math.random() > 0.7) {
      this.playChime();
    }

    this.comboCount++;
    if (this.comboCount % 10 === 0) {
      this.playWhaleSong();
    }
  }

  private playChime() {
    if (!this.ctx) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(880 + Math.random() * 440, this.ctx.currentTime);
    gain.gain.setValueAtTime(0.05, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 2);
    osc.connect(gain);
    gain.connect(this.ctx.destination);
    osc.start();
    osc.stop(this.ctx.currentTime + 2);
  }

  private playWhaleSong() {
    if (!this.ctx) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    const lfo = this.ctx.createOscillator();
    const lfoGain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(150, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(100, this.ctx.currentTime + 4);

    lfo.frequency.setValueAtTime(0.5, this.ctx.currentTime);
    lfoGain.gain.setValueAtTime(10, this.ctx.currentTime);

    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.05, this.ctx.currentTime + 1);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 4);

    lfo.connect(lfoGain);
    lfoGain.connect(osc.frequency);
    osc.connect(gain);
    gain.connect(this.ctx.destination);

    lfo.start();
    osc.start();
    osc.stop(this.ctx.currentTime + 4);
    lfo.stop(this.ctx.currentTime + 4);
  }
}

export const audioService = new AudioService();

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point } from './types';
import { QUOTES, COLORS, CONSTELLATIONS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const lastFireTime = useRef(0);

  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number}[]>([]);
  const requestRef = useRef<number>();

  // Initialize Stars
  useEffect(() => {
    const stars = [];
    for (let i = 0; i < 200; i++) {
      stars.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight * 0.7,
        s: Math.random() * 2,
        a: Math.random(),
        t: Math.random() * 100
      });
    }
    backgroundStars.current = stars;
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = power * 40 + 20;
    const layers = power > 2.5 ? 3 : (power > 1.5 ? 2 : 1);

    // Layer 1: Core Burst
    const isSpecial = Math.random() > 0.9;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 3 + 2) * power;
      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: 0.8 + Math.random() * 0.5,
        color,
        size: 2 + Math.random() * 2,
        friction: 0.96,
        gravity: 0.05,
        trail: [],
        shape: isSpecial ? 'star' : 'circle'
      };
      particles.current.push(p);
    }

    // Layer 2: Secondary Ring
    if (layers >= 2) {
      const subCount = count * 0.8;
      for (let i = 0; i < subCount; i++) {
        const angle = (Math.PI * 2 / subCount) * i;
        const speed = (Math.random() * 1.5 + 4) * power;
        const p: Particle = {
          x, y,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          life: 1,
          maxLife: 1.2,
          color: '#FFFFFF', // Sparkle white
          size: 1.5,
          friction: 0.94,
          gravity: 0.08,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Layer 3: Falling Dust
    if (layers >= 3) {
      for (let i = 0; i < 50; i++) {
        const p: Particle = {
          x: x + (Math.random() - 0.5) * 40,
          y: y + (Math.random() - 0.5) * 40,
          vx: (Math.random() - 0.5) * 2,
          vy: Math.random() * 2,
          life: 1,
          maxLife: 2.5,
          color: '#FFFFAA',
          size: 1,
          friction: 0.99,
          gravity: 0.02,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Surprise: Constellation pattern
    if (Math.random() > 0.9) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 30 * power;
      const rotation = Math.random() * Math.PI * 2;
      const cosR = Math.cos(rotation);
      const sinR = Math.sin(rotation);

      constellation.points.forEach(([px, py]) => {
        // Rotate and scale
        const rx = px * cosR - py * sinR;
        const ry = px * sinR + py * cosR;
        const p: Particle = {
          x: x + rx * scale,
          y: y + ry * scale,
          vx: 0,
          vy: 0,
          life: 1,
          maxLife: 3,
          color: '#ADD8E6',
          size: 3,
          friction: 1,
          gravity: 0,
          trail: []
        };
        particles.current.push(p);
      });
    }

    // Add Blessing Text
    const quote = QUOTES[Math.floor(Math.random() * QUOTES.length)];
    setBlessings(prev => [...prev.slice(-3), { text: quote, opacity: 1, y: y - 50, id: Date.now() }]);

    audioService.playPop(power);
  }, []);

  const triggerGalaxyFall = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 100; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        const p: Particle = {
          x: x,
          y: -10,
          vx: (Math.random() - 0.5) * 1,
          vy: Math.random() * 5 + 2,
          life: 1,
          maxLife: 4,
          color: '#E0F0FF',
          size: 1.5,
          friction: 0.99,
          gravity: 0.01,
          trail: []
        };
        particles.current.push(p);
      }, i * 20);
    }
  }, []);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const color = COLORS[Math.floor(Math.random() * COLORS.length)];
    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 100,
      y: canvas.height,
      targetY: y,
      vx: (x - canvas.width / 2) / 60,
      vy: -12 - power * 2,
      color,
      power,
      trail: [],
      active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    // Combo Logic
    const now = Date.now();
    if (now - lastFireTime.current < 3000) {
      setCombo(c => {
        const next = c + 1;
        if (next === 5) triggerGalaxyFall();
        return next;
      });
    } else {
      setCombo(1);
    }
    lastFireTime.current = now;
  }, [triggerGalaxyFall]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;

    // Background Gradient
    const grad = ctx.createLinearGradient(0, 0, 0, height);
    grad.addColorStop(0, '#02020a');
    grad.addColorStop(0.5, '#050518');
    grad.addColorStop(1, '#0c0c28');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, width, height);

    // Draw Aurora
    const time = Date.now() / 2000;
    ctx.save();
    ctx.globalCompositeOperation = 'lighter';
    for (let i = 0; i < 3; i++) {
      const aGrad = ctx.createLinearGradient(0, 0, width, 0);
      aGrad.addColorStop(0, 'rgba(0, 255, 128, 0)');
      aGrad.addColorStop(0.5, `rgba(0, 255, ${150 + i * 30}, 0.03)`);
      aGrad.addColorStop(1, 'rgba(255, 100, 255, 0)');
      ctx.fillStyle = aGrad;
      ctx.beginPath();
      ctx.moveTo(0, height * 0.3);
      for (let x = 0; x < width; x += 50) {
        const offset = Math.sin(x * 0.002 + time + i) * 100;
        ctx.lineTo(x, height * 0.2 + offset);
      }
      ctx.lineTo(width, height);
      ctx.lineTo(0, height);
      ctx.fill();
    }
    ctx.restore();

    // Draw Stars
    backgroundStars.current.forEach(star => {
      star.t += 0.02;
      const alpha = star.a * (0.5 + Math.sin(star.t) * 0.5);
      ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
      ctx.beginPath();
      ctx.arc(star.x, star.y, star.s, 0, Math.PI * 2);
      ctx.fill();
    });

    // Draw Mountains Silhouette
    ctx.fillStyle = '#020208';
    ctx.beginPath();
    ctx.moveTo(0, height);
    ctx.lineTo(0, height - 100);
    ctx.quadraticCurveTo(width * 0.25, height - 180, width * 0.5, height - 120);
    ctx.quadraticCurveTo(width * 0.75, height - 200, width, height - 80);
    ctx.lineTo(width, height);
    ctx.fill();

    // Draw Moonlight Glow on Mountain
    const moonGlow = ctx.createRadialGradient(width/2, height, 0, width/2, height, height);
    moonGlow.addColorStop(0, 'rgba(100, 100, 255, 0.1)');
    moonGlow.addColorStop(1, 'rgba(0, 0, 0, 0)');
    ctx.fillStyle = moonGlow;
    ctx.fillRect(0, height - 250, width, 250);

    // Update Projectiles
    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += 0.15; // Gravity on projectile

      p.trail.push({ x: p.x, y: p.y });
      if (p.trail.length > 20) p.trail.shift();

      ctx.beginPath();
      ctx.strokeStyle = p.color;
      ctx.lineWidth = 2;
      p.trail.forEach((pos, idx) => {
        if (idx === 0) ctx.moveTo(pos.x, pos.y);
        else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke();

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    // Update Particles
    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction;
      p.vy *= p.friction;
      p.vy += p.gravity;
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        if (p.shape === 'star') {
          // simple star
          const r = p.size;
          ctx.beginPath();
          for(let i=0; i<5; i++) {
            const a = (Math.PI*2/5)*i - Math.PI/2;
            const x = p.x + Math.cos(a)*r;
            const y = p.y + Math.sin(a)*r;
            if(i===0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
            const a2 = a + Math.PI/5;
            ctx.lineTo(p.x + Math.cos(a2)*r/2, p.y + Math.sin(a2)*r/2);
          }
          ctx.closePath();
          ctx.fill();
        } else {
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.globalAlpha = 1;
      }
    });

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    requestRef.current = requestAnimationFrame(() => update(ctx));

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', resize);
    };
  }, [update]);

  useEffect(() => {
    let timer: number;
    if (charging) {
      timer = window.setInterval(() => {
        setChargeLevel(prev => Math.min(prev + 0.05, 3));
      }, 30);
    }
    return () => clearInterval(timer);
  }, [charging]);

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    setCharging(true);
    setChargeLevel(0.5);
  };

  const handleMouseUp = (e: any) => {
    if (!charging) return;
    setCharging(false);
    const clientX = e.clientX || (e.changedTouches && e.changedTouches[0].clientX);
    const clientY = e.clientY || (e.changedTouches && e.changedTouches[0].clientY);
    launchFirework(clientX, clientY, chargeLevel);
    setChargeLevel(0);
  };

  // Update Blessings Animation
  useEffect(() => {
    const timer = setInterval(() => {
      setBlessings(prev => prev.map(b => ({
        ...b,
        y: b.y - 0.5,
        opacity: b.opacity - 0.005
      })).filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(timer);
  }, []);

  return (
    <div 
      className="relative w-full h-screen overflow-hidden"
      onMouseDown={handleMouseDown}
      onMouseUp={handleMouseUp}
      onTouchStart={handleMouseDown}
      onTouchEnd={handleMouseUp}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      {/* UI Overlay */}
      <div className="absolute top-8 left-0 right-0 pointer-events-none flex flex-col items-center">
        <h1 className="text-white text-3xl font-poetic tracking-widest opacity-80 mb-2">星愿·夜穹</h1>
        <p className="text-blue-200/50 text-xs tracking-tighter">长按蓄力 • 释放心愿</p>
      </div>

      {/* Charge Bar */}
      {charging && (
        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 w-48 h-1 bg-white/10 rounded-full overflow-hidden">
          <div 
            className="h-full bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 transition-all duration-75"
            style={{ width: `${(chargeLevel / 3) * 100}%` }}
          />
        </div>
      )}

      {/* Combo Badge */}
      {combo > 1 && (
        <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce">
          <span className="text-yellow-300 font-bold text-xl drop-shadow-[0_0_10px_rgba(255,255,0,0.5)]">
            {combo}连绽!
          </span>
        </div>
      )}

      {/* Floating Blessings */}
      {blessings.map(b => (
        <div 
          key={b.id}
          className="absolute left-1/2 -translate-x-1/2 pointer-events-none font-poetic text-white text-2xl whitespace-nowrap drop-shadow-[0_0_8px_rgba(255,255,255,0.8)]"
          style={{ top: `${b.y}px`, opacity: b.opacity }}
        >
          {b.text}
        </div>
      ))}

      {/* Footer Info */}
      <div className="absolute bottom-4 right-6 text-white/30 text-[10px] pointer-events-none">
        {new Date().getHours() >= 23 || new Date().getHours() < 1 ? '午夜特典：星尘入梦' : '当前：寂静深夜'}
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point } from './types';
import { QUOTES, COLORS, CONSTELLATIONS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const lastFireTime = useRef(0);

  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number}[]>([]);
  const requestRef = useRef<number>();

  // Initialize Stars
  useEffect(() => {
    const stars = [];
    for (let i = 0; i < 200; i++) {
      stars.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight * 0.7,
        s: Math.random() * 2,
        a: Math.random(),
        t: Math.random() * 100
      });
    }
    backgroundStars.current = stars;
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 40 + 20);
    const layers = power > 2.5 ? 3 : (power > 1.5 ? 2 : 1);

    // Layer 1: Core Burst
    const isSpecial = Math.random() > 0.9;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 3 + 2) * power;
      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: 0.8 + Math.random() * 0.5,
        color,
        size: 2 + Math.random() * 2,
        friction: 0.96,
        gravity: 0.05,
        trail: [],
        shape: isSpecial ? 'star' : 'circle'
      };
      particles.current.push(p);
    }

    // Layer 2: Secondary Ring
    if (layers >= 2) {
      const subCount = Math.floor(count * 0.8);
      for (let i = 0; i < subCount; i++) {
        const angle = (Math.PI * 2 / subCount) * i;
        const speed = (Math.random() * 1.5 + 4) * power;
        const p: Particle = {
          x, y,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          life: 1,
          maxLife: 1.2,
          color: '#FFFFFF',
          size: 1.5,
          friction: 0.94,
          gravity: 0.08,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Layer 3: Falling Dust
    if (layers >= 3) {
      for (let i = 0; i < 50; i++) {
        const p: Particle = {
          x: x + (Math.random() - 0.5) * 40,
          y: y + (Math.random() - 0.5) * 40,
          vx: (Math.random() - 0.5) * 2,
          vy: Math.random() * 2,
          life: 1,
          maxLife: 2.5,
          color: '#FFFFAA',
          size: 1,
          friction: 0.99,
          gravity: 0.02,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Surprise: Constellation pattern
    if (Math.random() > 0.9) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 30 * power;
      const rotation = Math.random() * Math.PI * 2;
      const cosR = Math.cos(rotation);
      const sinR = Math.sin(rotation);

      constellation.points.forEach(([px, py]) => {
        const rx = px * cosR - py * sinR;
        const ry = px * sinR + py * cosR;
        const p: Particle = {
          x: x + rx * scale,
          y: y + ry * scale,
          vx: 0,
          vy: 0,
          life: 1,
          maxLife: 3,
          color: '#ADD8E6',
          size: 3,
          friction: 1,
          gravity: 0,
          trail: []
        };
        particles.current.push(p);
      });
    }

    const quote = QUOTES[Math.floor(Math.random() * QUOTES.length)];
    setBlessings(prev => [...prev.slice(-3), { text: quote, opacity: 1, y: y - 50, id: Date.now() }]);

    audioService.playPop(power);
  }, []);

  const triggerGalaxyFall = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 100; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        const p: Particle = {
          x: x,
          y: -10,
          vx: (Math.random() - 0.5) * 1,
          vy: Math.random() * 5 + 2,
          life: 1,
          maxLife: 4,
          color: '#E0F0FF',
          size: 1.5,
          friction: 0.99,
          gravity: 0.01,
          trail: []
        };
        particles.current.push(p);
      }, i * 20);
    }
  }, []);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const color = COLORS[Math.floor(Math.random() * COLORS.length)];
    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 100,
      y: canvas.height,
      targetY: y,
      vx: (x - canvas.width / 2) / 60,
      vy: -12 - power * 2,
      color,
      power,
      trail: [],
      active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    const now = Date.now();
    if (now - lastFireTime.current < 3000) {
      setCombo(c => {
        const next = c + 1;
        if (next === 5) triggerGalaxyFall();
        return next;
      });
    } else {
      setCombo(1);
    }
    lastFireTime.current = now;
  }, [triggerGalaxyFall]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;

    const grad = ctx.createLinearGradient(0, 0, 0, height);
    grad.addColorStop(0, '#02020a');
    grad.addColorStop(0.5, '#050518');
    grad.addColorStop(1, '#0c0c28');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, width, height);

    const time = Date.now() / 2000;
    ctx.save();
    ctx.globalCompositeOperation = 'lighter';
    for (let i = 0; i < 3; i++) {
      const aGrad = ctx.createLinearGradient(0, 0, width, 0);
      aGrad.addColorStop(0, 'rgba(0, 255, 128, 0)');
      aGrad.addColorStop(0.5, `rgba(0, 255, ${150 + i * 30}, 0.03)`);
      aGrad.addColorStop(1, 'rgba(255, 100, 255, 0)');
      ctx.fillStyle = aGrad;
      ctx.beginPath();
      ctx.moveTo(0, height * 0.3);
      for (let x = 0; x < width; x += 50) {
        const offset = Math.sin(x * 0.002 + time + i) * 100;
        ctx.lineTo(x, height * 0.2 + offset);
      }
      ctx.lineTo(width, height);
      ctx.lineTo(0, height);
      ctx.fill();
    }
    ctx.restore();

    backgroundStars.current.forEach(star => {
      star.t += 0.02;
      const alpha = star.a * (0.5 + Math.sin(star.t) * 0.5);
      ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
      ctx.beginPath();
      ctx.arc(star.x, star.y, star.s, 0, Math.PI * 2);
      ctx.fill();
    });

    ctx.fillStyle = '#020208';
    ctx.beginPath();
    ctx.moveTo(0, height);
    ctx.lineTo(0, height - 100);
    ctx.quadraticCurveTo(width * 0.25, height - 180, width * 0.5, height - 120);
    ctx.quadraticCurveTo(width * 0.75, height - 200, width, height - 80);
    ctx.lineTo(width, height);
    ctx.fill();

    const moonGlow = ctx.createRadialGradient(width/2, height, 0, width/2, height, height);
    moonGlow.addColorStop(0, 'rgba(100, 100, 255, 0.1)');
    moonGlow.addColorStop(1, 'rgba(0, 0, 0, 0)');
    ctx.fillStyle = moonGlow;
    ctx.fillRect(0, height - 250, width, 250);

    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += 0.15;

      p.trail.push({ x: p.x, y: p.y });
      if (p.trail.length > 20) p.trail.shift();

      ctx.beginPath();
      ctx.strokeStyle = p.color;
      ctx.lineWidth = 2;
      p.trail.forEach((pos, idx) => {
        if (idx === 0) ctx.moveTo(pos.x, pos.y);
        else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke();

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction;
      p.vy *= p.friction;
      p.vy += p.gravity;
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        if (p.shape === 'star') {
          const r = p.size;
          ctx.beginPath();
          for(let i=0; i<5; i++) {
            const a = (Math.PI*2/5)*i - Math.PI/2;
            const x = p.x + Math.cos(a)*r;
            const y = p.y + Math.sin(a)*r;
            if(i===0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
            const a2 = a + Math.PI/5;
            ctx.lineTo(p.x + Math.cos(a2)*r/2, p.y + Math.sin(a2)*r/2);
          }
          ctx.closePath();
          ctx.fill();
        } else {
          ctx.beginPath();
          ctx.arc(p.x, p.y, Math.max(0.1, p.size * p.life), 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.globalAlpha = 1;
      }
    });

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    requestRef.current = requestAnimationFrame(() => update(ctx));

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', resize);
    };
  }, [update]);

  useEffect(() => {
    let timer: number;
    if (charging) {
      timer = window.setInterval(() => {
        setChargeLevel(prev => Math.min(prev + 0.05, 3));
      }, 30);
    }
    return () => clearInterval(timer);
  }, [charging]);

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    // Prevent default to avoid simulated mouse events on touch devices
    if ('cancelable' in e && e.cancelable) {
      e.preventDefault();
    }
    setCharging(true);
    setChargeLevel(0.5);
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (!charging) return;
    if ('cancelable' in e && e.cancelable) {
      e.preventDefault();
    }

    setCharging(false);

    let clientX = 0;
    let clientY = 0;

    if ('touches' in e && e.changedTouches.length > 0) {
      clientX = e.changedTouches[0].clientX;
      clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    launchFirework(clientX, clientY, chargeLevel);
    setChargeLevel(0);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      setBlessings(prev => prev.map(b => ({
        ...b,
        y: b.y - 0.5,
        opacity: b.opacity - 0.005
      })).filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(timer);
  }, []);

  return (
    <div 
      className="relative w-full h-screen overflow-hidden touch-none"
      onMouseDown={handleStart}
      onMouseUp={handleEnd}
      onTouchStart={handleStart}
      onTouchEnd={handleEnd}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      <div className="absolute top-8 left-0 right-0 pointer-events-none flex flex-col items-center">
        <h1 className="text-white text-3xl font-poetic tracking-widest opacity-80 mb-2">星愿·夜穹</h1>
        <p className="text-blue-200/50 text-xs tracking-tighter">长按蓄力 • 释放心愿</p>
      </div>

      {charging && (
        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 w-48 h-1 bg-white/10 rounded-full overflow-hidden">
          <div 
            className="h-full bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 transition-all duration-75"
            style={{ width: `${(chargeLevel / 3) * 100}%` }}
          />
        </div>
      )}

      {combo > 1 && (
        <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce">
          <span className="text-yellow-300 font-bold text-xl drop-shadow-[0_0_10px_rgba(255,255,0,0.5)]">
            {combo}连绽!
          </span>
        </div>
      )}

      {blessings.map(b => (
        <div 
          key={b.id}
          className="absolute left-1/2 -translate-x-1/2 pointer-events-none font-poetic text-white text-2xl whitespace-nowrap drop-shadow-[0_0_8px_rgba(255,255,255,0.8)]"
          style={{ top: `${b.y}px`, opacity: b.opacity }}
        >
          {b.text}
        </div>
      ))}

      <div className="absolute bottom-4 right-6 text-white/30 text-[10px] pointer-events-none">
        {new Date().getHours() >= 23 || new Date().getHours() < 1 ? '午夜特典：星尘入梦' : '当前：寂静深夜'}
      </div>
    </div>
  );
};

