import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point, HolidayConfig } from './types';
import { QUOTES, COLORS, CONSTELLATIONS, HOLIDAYS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const [activeHoliday, setActiveHoliday] = useState<HolidayConfig | null>(null);
  const [showHolidaySplash, setShowHolidaySplash] = useState(false);

  const lastFireTime = useRef(0);
  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number}[]>([]);
  const requestRef = useRef<number>();

  // Check for Holiday on Mount
  useEffect(() => {
    const now = new Date();
    const holiday = HOLIDAYS.find(h => h.match(now));
    if (holiday) {
      setActiveHoliday(holiday);

      // Check if first launch for this holiday
      const storageKey = `holiday_splash_${holiday.id}_${now.getFullYear()}`;
      if (holiday.firstLaunchEffect && !localStorage.getItem(storageKey)) {
        setShowHolidaySplash(true);
        localStorage.setItem(storageKey, 'true');

        // Auto-close splash after 4 seconds
        setTimeout(() => setShowHolidaySplash(false), 4000);
      }
    }
  }, []);

  // Initialize Stars
  useEffect(() => {
    const stars = [];
    for (let i = 0; i < 200; i++) {
      stars.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight * 0.7,
        s: Math.random() * 2,
        a: Math.random(),
        t: Math.random() * 100
      });
    }
    backgroundStars.current = stars;
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 40 + 20);
    const layers = power > 2.5 ? 3 : (power > 1.5 ? 2 : 1);

    // Use Holiday Colors if active
    const finalColors = (activeHoliday && Math.random() > 0.3) ? activeHoliday.specialColors : [color];
    const particleColor = finalColors[Math.floor(Math.random() * finalColors.length)];

    // Layer 1: Core Burst
    const isSpecial = Math.random() > 0.9;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 3 + 2) * power;
      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: 0.8 + Math.random() * 0.5,
        color: particleColor,
        size: 2 + Math.random() * 2,
        friction: 0.96,
        gravity: 0.05,
        trail: [],
        shape: isSpecial ? 'star' : 'circle'
      };
      particles.current.push(p);
    }

    // Layer 2: Secondary Ring
    if (layers >= 2) {
      const subCount = Math.floor(count * 0.8);
      for (let i = 0; i < subCount; i++) {
        const angle = (Math.PI * 2 / subCount) * i;
        const speed = (Math.random() * 1.5 + 4) * power;
        const p: Particle = {
          x, y,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          life: 1,
          maxLife: 1.2,
          color: '#FFFFFF',
          size: 1.5,
          friction: 0.94,
          gravity: 0.08,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Layer 3: Falling Dust
    if (layers >= 3) {
      for (let i = 0; i < 50; i++) {
        const p: Particle = {
          x: x + (Math.random() - 0.5) * 40,
          y: y + (Math.random() - 0.5) * 40,
          vx: (Math.random() - 0.5) * 2,
          vy: Math.random() * 2,
          life: 1,
          maxLife: 2.5,
          color: activeHoliday?.id === 'new_year_eve' ? '#FFD700' : '#FFFFAA',
          size: 1,
          friction: 0.99,
          gravity: 0.02,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Surprise: Constellation pattern
    if (Math.random() > 0.9) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 30 * power;
      const rotation = Math.random() * Math.PI * 2;
      const cosR = Math.cos(rotation);
      const sinR = Math.sin(rotation);

      constellation.points.forEach(([px, py]) => {
        const rx = px * cosR - py * sinR;
        const ry = px * sinR + py * cosR;
        const p: Particle = {
          x: x + rx * scale,
          y: y + ry * scale,
          vx: 0,
          vy: 0,
          life: 1,
          maxLife: 3,
          color: '#ADD8E6',
          size: 3,
          friction: 1,
          gravity: 0,
          trail: []
        };
        particles.current.push(p);
      });
    }

    const holidayQuotes = activeHoliday?.specialQuotes || [];
    const pool = holidayQuotes.length > 0 && Math.random() > 0.5 ? holidayQuotes : QUOTES;
    const quote = pool[Math.floor(Math.random() * pool.length)];

    setBlessings(prev => [...prev.slice(-3), { 
      text: quote, 
      opacity: 1, 
      y: y - 50, 
      id: Date.now(),
      scale: activeHoliday ? 1.2 : 1
    }]);

    audioService.playPop(power);
  }, [activeHoliday]);

  const triggerGalaxyFall = useCallback((customColor?: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 100; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        const p: Particle = {
          x: x,
          y: -10,
          vx: (Math.random() - 0.5) * 1,
          vy: Math.random() * 5 + 2,
          life: 1,
          maxLife: 4,
          color: customColor || '#E0F0FF',
          size: 1.5,
          friction: 0.99,
          gravity: 0.01,
          trail: []
        };
        particles.current.push(p);
      }, i * 20);
    }
  }, []);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    let color = COLORS[Math.floor(Math.random() * COLORS.length)];
    if (activeHoliday) {
      color = activeHoliday.specialColors[Math.floor(Math.random() * activeHoliday.specialColors.length)];
    }

    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 100,
      y: canvas.height,
      targetY: y,
      vx: (x - canvas.width / 2) / 60,
      vy: -12 - power * 2,
      color,
      power,
      trail: [],
      active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    const now = Date.now();
    if (now - lastFireTime.current < 3000) {
      setCombo(c => {
        const next = c + 1;
        if (next === 5) {
          const fallColor = activeHoliday?.id === 'new_year_eve' ? '#FFD700' : (activeHoliday?.id === 'spring_festival' ? '#FF0000' : undefined);
          triggerGalaxyFall(fallColor);
        }
        return next;
      });
    } else {
      setCombo(1);
    }
    lastFireTime.current = now;
  }, [triggerGalaxyFall, activeHoliday]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;

    const grad = ctx.createLinearGradient(0, 0, 0, height);
    grad.addColorStop(0, '#02020a');
    grad.addColorStop(0.5, '#050518');
    grad.addColorStop(1, '#0c0c28');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, width, height);

    const time = Date.now() / 2000;
    ctx.save();
    ctx.globalCompositeOperation = 'lighter';
    for (let i = 0; i < 3; i++) {
      const aGrad = ctx.createLinearGradient(0, 0, width, 0);
      aGrad.addColorStop(0, 'rgba(0, 255, 128, 0)');
      aGrad.addColorStop(0.5, `rgba(0, 255, ${150 + i * 30}, 0.03)`);
      aGrad.addColorStop(1, 'rgba(255, 100, 255, 0)');
      ctx.fillStyle = aGrad;
      ctx.beginPath();
      ctx.moveTo(0, height * 0.3);
      for (let x = 0; x < width; x += 50) {
        const offset = Math.sin(x * 0.002 + time + i) * 100;
        ctx.lineTo(x, height * 0.2 + offset);
      }
      ctx.lineTo(width, height);
      ctx.lineTo(0, height);
      ctx.fill();
    }
    ctx.restore();

    backgroundStars.current.forEach(star => {
      star.t += 0.02;
      const alpha = star.a * (0.5 + Math.sin(star.t) * 0.5);
      ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
      ctx.beginPath();
      ctx.arc(star.x, star.y, star.s, 0, Math.PI * 2);
      ctx.fill();
    });

    ctx.fillStyle = '#020208';
    ctx.beginPath();
    ctx.moveTo(0, height);
    ctx.lineTo(0, height - 100);
    ctx.quadraticCurveTo(width * 0.25, height - 180, width * 0.5, height - 120);
    ctx.quadraticCurveTo(width * 0.75, height - 200, width, height - 80);
    ctx.lineTo(width, height);
    ctx.fill();

    const moonGlow = ctx.createRadialGradient(width/2, height, 0, width/2, height, height);
    moonGlow.addColorStop(0, 'rgba(100, 100, 255, 0.1)');
    moonGlow.addColorStop(1, 'rgba(0, 0, 0, 0)');
    ctx.fillStyle = moonGlow;
    ctx.fillRect(0, height - 250, width, 250);

    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += 0.15;

      p.trail.push({ x: p.x, y: p.y });
      if (p.trail.length > 20) p.trail.shift();

      ctx.beginPath();
      ctx.strokeStyle = p.color;
      ctx.lineWidth = 2;
      p.trail.forEach((pos, idx) => {
        if (idx === 0) ctx.moveTo(pos.x, pos.y);
        else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke();

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction;
      p.vy *= p.friction;
      p.vy += p.gravity;
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        if (p.shape === 'star') {
          const r = p.size;
          ctx.beginPath();
          for(let i=0; i<5; i++) {
            const a = (Math.PI*2/5)*i - Math.PI/2;
            const x = p.x + Math.cos(a)*r;
            const y = p.y + Math.sin(a)*r;
            if(i===0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
            const a2 = a + Math.PI/5;
            ctx.lineTo(p.x + Math.cos(a2)*r/2, p.y + Math.sin(a2)*r/2);
          }
          ctx.closePath();
          ctx.fill();
        } else {
          ctx.beginPath();
          ctx.arc(p.x, p.y, Math.max(0.1, p.size * p.life), 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.globalAlpha = 1;
      }
    });

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    requestRef.current = requestAnimationFrame(() => update(ctx));

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', resize);
    };
  }, [update]);

  useEffect(() => {
    let timer: number;
    if (charging) {
      timer = window.setInterval(() => {
        setChargeLevel(prev => Math.min(prev + 0.05, 3));
      }, 30);
    }
    return () => clearInterval(timer);
  }, [charging]);

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    if ('cancelable' in e && e.cancelable) {
      e.preventDefault();
    }
    setCharging(true);
    setChargeLevel(0.5);
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (!charging) return;
    if ('cancelable' in e && e.cancelable) {
      e.preventDefault();
    }

    setCharging(false);

    let clientX = 0;
    let clientY = 0;

    if ('touches' in e && e.changedTouches.length > 0) {
      clientX = e.changedTouches[0].clientX;
      clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    launchFirework(clientX, clientY, chargeLevel);
    setChargeLevel(0);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      setBlessings(prev => prev.map(b => ({
        ...b,
        y: b.y - 0.5,
        opacity: b.opacity - 0.005
      })).filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(timer);
  }, []);

  return (
    <div 
      className="relative w-full h-screen overflow-hidden touch-none"
      onMouseDown={handleStart}
      onMouseUp={handleEnd}
      onTouchStart={handleStart}
      onTouchEnd={handleEnd}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      {/* Holiday First Launch Splash */}
      {showHolidaySplash && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-red-700/80 transition-opacity duration-1000 animate-pulse pointer-events-none">
          <div className="text-center">
            <h2 className="text-yellow-400 font-poetic text-8xl drop-shadow-[0_0_20px_rgba(255,215,0,0.8)] animate-bounce">
              春节快乐
            </h2>
            <div className="mt-8 text-white/80 font-poetic text-2xl tracking-widest">
              祥龙献瑞 · 岁岁平安
            </div>
          </div>
        </div>
      )}

      <div className="absolute top-8 left-0 right-0 pointer-events-none flex flex-col items-center">
        <h1 className="text-white text-3xl font-poetic tracking-widest opacity-80 mb-2">
          {activeHoliday?.name ? `星愿·夜穹 (${activeHoliday.name})` : '星愿·夜穹'}
        </h1>
        <p className="text-blue-200/50 text-xs tracking-tighter">长按蓄力 • 释放心愿</p>
      </div>

      {charging && (
        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 w-48 h-1 bg-white/10 rounded-full overflow-hidden">
          <div 
            className="h-full bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 transition-all duration-75"
            style={{ width: `${(chargeLevel / 3) * 100}%` }}
          />
        </div>
      )}

      {combo > 1 && (
        <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce">
          <span className="text-yellow-300 font-bold text-xl drop-shadow-[0_0_10px_rgba(255,255,0,0.5)]">
            {combo}连绽!
          </span>
        </div>
      )}

      {blessings.map(b => (
        <div 
          key={b.id}
          className="absolute left-1/2 -translate-x-1/2 pointer-events-none font-poetic text-white text-2xl whitespace-nowrap drop-shadow-[0_0_8px_rgba(255,255,255,0.8)]"
          style={{ 
            top: `${b.y}px`, 
            opacity: b.opacity,
            transform: `translateX(-50%) scale(${b.scale || 1})`
          }}
        >
          {b.text}
        </div>
      ))}

      <div className="absolute bottom-4 right-6 text-white/30 text-[10px] pointer-events-none">
        {activeHoliday ? `今日：${activeHoliday.name}` : (new Date().getHours() >= 23 || new Date().getHours() < 1 ? '午夜特典：星尘入梦' : '当前：寂静深夜')}
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point, HolidayConfig } from './types';
import { QUOTES, ANCIENT_QUOTES, COLORS, SUMI_COLORS, CONSTELLATIONS, HOLIDAYS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const [activeHoliday, setActiveHoliday] = useState<HolidayConfig | null>(null);
  const [showHolidaySplash, setShowHolidaySplash] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  const lastFireTime = useRef(0);
  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number}[]>([]);
  const requestRef = useRef<number>();

  // Online/Offline Listeners
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Check for Holiday on Mount
  useEffect(() => {
    const now = new Date();
    const holiday = HOLIDAYS.find(h => h.match(now));
    if (holiday) {
      setActiveHoliday(holiday);

      const storageKey = `holiday_splash_${holiday.id}_${now.getFullYear()}`;
      if (holiday.firstLaunchEffect && !localStorage.getItem(storageKey)) {
        setShowHolidaySplash(true);
        localStorage.setItem(storageKey, 'true');
        setTimeout(() => setShowHolidaySplash(false), 4000);
      }
    }
  }, []);

  // Initialize Stars
  useEffect(() => {
    const stars = [];
    for (let i = 0; i < 200; i++) {
      stars.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight * 0.7,
        s: Math.random() * 2,
        a: Math.random(),
        t: Math.random() * 100
      });
    }
    backgroundStars.current = stars;
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 40 + 20);
    const layers = power > 2.5 ? 3 : (power > 1.5 ? 2 : 1);

    // Color Logic: Sumi-e for Offline, Holiday or Default for Online
    let particleColor: string;
    if (isOffline) {
      particleColor = SUMI_COLORS[Math.floor(Math.random() * SUMI_COLORS.length)];
    } else {
      const finalColors = (activeHoliday && Math.random() > 0.3) ? activeHoliday.specialColors : [color];
      particleColor = finalColors[Math.floor(Math.random() * finalColors.length)];
    }

    // Layer 1: Core Burst
    const isSpecial = Math.random() > 0.9;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 3 + 2) * power;
      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: isOffline ? 1.5 : 0.8 + Math.random() * 0.5, // Offline lasts longer for ink bleeding effect
        color: particleColor,
        size: isOffline ? 4 + Math.random() * 4 : 2 + Math.random() * 2, // Larger particles for Sumi-e
        friction: isOffline ? 0.94 : 0.96, // More friction for thicker ink feel
        gravity: isOffline ? 0.08 : 0.05,
        trail: [],
        shape: isSpecial ? 'star' : 'circle'
      };
      particles.current.push(p);
    }

    // Layer 2: Secondary Ring / Ink Bleed
    if (layers >= 2) {
      const subCount = Math.floor(count * 0.8);
      for (let i = 0; i < subCount; i++) {
        const angle = (Math.PI * 2 / subCount) * i;
        const speed = (Math.random() * 1.5 + 4) * power;
        const p: Particle = {
          x, y,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          life: 1,
          maxLife: 1.2,
          color: isOffline ? '#444444' : '#FFFFFF',
          size: isOffline ? 2 : 1.5,
          friction: 0.94,
          gravity: 0.08,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Layer 3: Falling Dust / Ink Splatter
    if (layers >= 3) {
      for (let i = 0; i < 50; i++) {
        const p: Particle = {
          x: x + (Math.random() - 0.5) * 40,
          y: y + (Math.random() - 0.5) * 40,
          vx: (Math.random() - 0.5) * 2,
          vy: Math.random() * 2,
          life: 1,
          maxLife: 2.5,
          color: isOffline ? '#222222' : (activeHoliday?.id === 'new_year_eve' ? '#FFD700' : '#FFFFAA'),
          size: isOffline ? 2.5 : 1,
          friction: 0.99,
          gravity: 0.02,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Surprise: Constellation pattern
    if (!isOffline && Math.random() > 0.9) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 30 * power;
      const rotation = Math.random() * Math.PI * 2;
      const cosR = Math.cos(rotation);
      const sinR = Math.sin(rotation);

      constellation.points.forEach(([px, py]) => {
        const rx = px * cosR - py * sinR;
        const ry = px * sinR + py * cosR;
        const p: Particle = {
          x: x + rx * scale,
          y: y + ry * scale,
          vx: 0,
          vy: 0,
          life: 1,
          maxLife: 3,
          color: '#ADD8E6',
          size: 3,
          friction: 1,
          gravity: 0,
          trail: []
        };
        particles.current.push(p);
      });
    }

    // Quote Selection
    const holidayQuotes = activeHoliday?.specialQuotes || [];
    const quotePool = isOffline ? ANCIENT_QUOTES : (holidayQuotes.length > 0 && Math.random() > 0.5 ? holidayQuotes : QUOTES);
    const quote = quotePool[Math.floor(Math.random() * quotePool.length)];

    setBlessings(prev => [...prev.slice(-3), { 
      text: quote, 
      opacity: 1, 
      y: y - 50, 
      id: Date.now(),
      scale: activeHoliday ? 1.2 : 1
    }]);

    audioService.playPop(power);
  }, [activeHoliday, isOffline]);

  const triggerGalaxyFall = useCallback((customColor?: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 100; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        const p: Particle = {
          x: x,
          y: -10,
          vx: (Math.random() - 0.5) * 1,
          vy: Math.random() * 5 + 2,
          life: 1,
          maxLife: 4,
          color: customColor || (isOffline ? '#333333' : '#E0F0FF'),
          size: 1.5,
          friction: 0.99,
          gravity: 0.01,
          trail: []
        };
        particles.current.push(p);
      }, i * 20);
    }
  }, [isOffline]);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    let color = isOffline ? '#1a1a1a' : COLORS[Math.floor(Math.random() * COLORS.length)];
    if (!isOffline && activeHoliday) {
      color = activeHoliday.specialColors[Math.floor(Math.random() * activeHoliday.specialColors.length)];
    }

    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 100,
      y: canvas.height,
      targetY: y,
      vx: (x - canvas.width / 2) / 60,
      vy: -12 - power * 2,
      color,
      power,
      trail: [],
      active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    const now = Date.now();
    if (now - lastFireTime.current < 3000) {
      setCombo(c => {
        const next = c + 1;
        if (next === 5) {
          const fallColor = isOffline ? '#1a1a1a' : (activeHoliday?.id === 'new_year_eve' ? '#FFD700' : (activeHoliday?.id === 'spring_festival' ? '#FF0000' : undefined));
          triggerGalaxyFall(fallColor);
        }
        return next;
      });
    } else {
      setCombo(1);
    }
    lastFireTime.current = now;
  }, [triggerGalaxyFall, activeHoliday, isOffline]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;

    // Background logic
    if (isOffline) {
      // Offline: Sumi-e parchment texture
      ctx.fillStyle = '#f4f1ea'; // Light paper color
      ctx.fillRect(0, 0, width, height);
      // Add a bit of texture/grain
      ctx.fillStyle = 'rgba(0,0,0,0.02)';
      for(let i=0; i<100; i++) {
        ctx.fillRect(Math.random()*width, Math.random()*height, 2, 2);
      }
    } else {
      const grad = ctx.createLinearGradient(0, 0, 0, height);
      grad.addColorStop(0, '#02020a');
      grad.addColorStop(0.5, '#050518');
      grad.addColorStop(1, '#0c0c28');
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, width, height);

      // Aurora
      const time = Date.now() / 2000;
      ctx.save();
      ctx.globalCompositeOperation = 'lighter';
      for (let i = 0; i < 3; i++) {
        const aGrad = ctx.createLinearGradient(0, 0, width, 0);
        aGrad.addColorStop(0, 'rgba(0, 255, 128, 0)');
        aGrad.addColorStop(0.5, `rgba(0, 255, ${150 + i * 30}, 0.03)`);
        aGrad.addColorStop(1, 'rgba(255, 100, 255, 0)');
        ctx.fillStyle = aGrad;
        ctx.beginPath();
        ctx.moveTo(0, height * 0.3);
        for (let x = 0; x < width; x += 50) {
          const offset = Math.sin(x * 0.002 + time + i) * 100;
          ctx.lineTo(x, height * 0.2 + offset);
        }
        ctx.lineTo(width, height);
        ctx.lineTo(0, height);
        ctx.fill();
      }
      ctx.restore();

      backgroundStars.current.forEach(star => {
        star.t += 0.02;
        const alpha = star.a * (0.5 + Math.sin(star.t) * 0.5);
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.s, 0, Math.PI * 2);
        ctx.fill();
      });
    }

    // Mountain silhouette
    ctx.fillStyle = isOffline ? '#cccccc' : '#020208';
    ctx.beginPath();
    ctx.moveTo(0, height);
    ctx.lineTo(0, height - 100);
    ctx.quadraticCurveTo(width * 0.25, height - 180, width * 0.5, height - 120);
    ctx.quadraticCurveTo(width * 0.75, height - 200, width, height - 80);
    ctx.lineTo(width, height);
    ctx.fill();

    if (!isOffline) {
      const moonGlow = ctx.createRadialGradient(width/2, height, 0, width/2, height, height);
      moonGlow.addColorStop(0, 'rgba(100, 100, 255, 0.1)');
      moonGlow.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = moonGlow;
      ctx.fillRect(0, height - 250, width, 250);
    }

    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += 0.15;

      p.trail.push({ x: p.x, y: p.y });
      if (p.trail.length > 20) p.trail.shift();

      ctx.beginPath();
      ctx.strokeStyle = p.color;
      ctx.lineWidth = isOffline ? 4 : 2;
      p.trail.forEach((pos, idx) => {
        if (idx === 0) ctx.moveTo(pos.x, pos.y);
        else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke();

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction;
      p.vy *= p.friction;
      p.vy += p.gravity;
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = isOffline ? p.life * 0.8 : p.life;
        if (p.shape === 'star' && !isOffline) {
          const r = p.size;
          ctx.beginPath();
          for(let i=0; i<5; i++) {
            const a = (Math.PI*2/5)*i - Math.PI/2;
            const x = p.x + Math.cos(a)*r;
            const y = p.y + Math.sin(a)*r;
            if(i===0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
            const a2 = a + Math.PI/5;
            ctx.lineTo(p.x + Math.cos(a2)*r/2, p.y + Math.sin(a2)*r/2);
          }
          ctx.closePath();
          ctx.fill();
        } else {
          // Circle or Sumi-e "splat"
          ctx.beginPath();
          const currentSize = Math.max(0.1, p.size * p.life);
          if (isOffline) {
            // Slightly irregular ink droplets
            ctx.ellipse(p.x, p.y, currentSize, currentSize * (0.8 + Math.random() * 0.4), Math.random() * Math.PI, 0, Math.PI * 2);
          } else {
            ctx.arc(p.x, p.y, currentSize, 0, Math.PI * 2);
          }
          ctx.fill();
        }
        ctx.globalAlpha = 1;
      }
    });

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles, isOffline]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    requestRef.current = requestAnimationFrame(() => update(ctx));

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', resize);
    };
  }, [update]);

  useEffect(() => {
    let timer: number;
    if (charging) {
      timer = window.setInterval(() => {
        setChargeLevel(prev => Math.min(prev + 0.05, 3));
      }, 30);
    }
    return () => clearInterval(timer);
  }, [charging]);

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    if ('cancelable' in e && e.cancelable) {
      e.preventDefault();
    }
    setCharging(true);
    setChargeLevel(0.5);
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (!charging) return;
    if ('cancelable' in e && e.cancelable) {
      e.preventDefault();
    }

    setCharging(false);

    let clientX = 0;
    let clientY = 0;

    if ('touches' in e && e.changedTouches.length > 0) {
      clientX = e.changedTouches[0].clientX;
      clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    launchFirework(clientX, clientY, chargeLevel);
    setChargeLevel(0);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      setBlessings(prev => prev.map(b => ({
        ...b,
        y: b.y - (isOffline ? 0.3 : 0.5), // Slower rise in Sumi-e mode
        opacity: b.opacity - (isOffline ? 0.003 : 0.005) // Slower fade
      })).filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(timer);
  }, [isOffline]);

  return (
    <div 
      className={`relative w-full h-screen overflow-hidden touch-none transition-colors duration-1000 ${isOffline ? 'bg-[#f4f1ea]' : 'bg-[#050510]'}`}
      onMouseDown={handleStart}
      onMouseUp={handleEnd}
      onTouchStart={handleStart}
      onTouchEnd={handleEnd}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      {/* Holiday Splash */}
      {showHolidaySplash && !isOffline && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-red-700/80 transition-opacity duration-1000 animate-pulse pointer-events-none">
          <div className="text-center">
            <h2 className="text-yellow-400 font-poetic text-8xl drop-shadow-[0_0_20px_rgba(255,215,0,0.8)] animate-bounce">
              春节快乐
            </h2>
            <div className="mt-8 text-white/80 font-poetic text-2xl tracking-widest">
              祥龙献瑞 · 岁岁平安
            </div>
          </div>
        </div>
      )}

      <div className="absolute top-8 left-0 right-0 pointer-events-none flex flex-col items-center">
        <h1 className={`text-3xl font-poetic tracking-widest opacity-80 mb-2 transition-colors duration-1000 ${isOffline ? 'text-[#1a1a1a]' : 'text-white'}`}>
          {isOffline ? '墨染·心弦' : (activeHoliday?.name ? `星愿·夜穹 (${activeHoliday.name})` : '星愿·夜穹')}
        </h1>
        <p className={`text-xs tracking-tighter transition-colors duration-1000 ${isOffline ? 'text-[#1a1a1a]/50' : 'text-blue-200/50'}`}>
          {isOffline ? '静心长按 • 泼墨成愿' : '长按蓄力 • 释放心愿'}
        </p>
      </div>

      {charging && (
        <div className={`absolute bottom-12 left-1/2 -translate-x-1/2 w-48 h-1 rounded-full overflow-hidden transition-colors ${isOffline ? 'bg-[#1a1a1a]/10' : 'bg-white/10'}`}>
          <div 
            className={`h-full transition-all duration-75 ${isOffline ? 'bg-[#1a1a1a]' : 'bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400'}`}
            style={{ width: `${(chargeLevel / 3) * 100}%` }}
          />
        </div>
      )}

      {combo > 1 && (
        <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce">
          <span className={`font-bold text-xl drop-shadow-[0_0_10px_rgba(0,0,0,0.1)] ${isOffline ? 'text-[#b22222]' : 'text-yellow-300'}`}>
            {combo}{isOffline ? '连笔!' : '连绽!'}
          </span>
        </div>
      )}

      {blessings.map(b => (
        <div 
          key={b.id}
          className={`absolute left-1/2 -translate-x-1/2 pointer-events-none font-poetic text-2xl whitespace-nowrap transition-colors duration-1000 ${isOffline ? 'text-[#1a1a1a] drop-shadow-none' : 'text-white drop-shadow-[0_0_8px_rgba(255,255,255,0.8)]'}`}
          style={{ 
            top: `${b.y}px`, 
            opacity: b.opacity,
            transform: `translateX(-50%) scale(${b.scale || 1})`,
            writingMode: isOffline ? 'vertical-rl' : 'horizontal-tb'
          }}
        >
          {b.text}
        </div>
      ))}

      <div className={`absolute bottom-4 right-6 text-[10px] pointer-events-none transition-colors duration-1000 ${isOffline ? 'text-[#1a1a1a]/20' : 'text-white/30'}`}>
        {isOffline ? '断网模式：水墨横斜' : (activeHoliday ? `今日：${activeHoliday.name}` : (new Date().getHours() >= 23 || new Date().getHours() < 1 ? '午夜特典：星尘入梦' : '当前：寂静深夜'))}
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point, HolidayConfig } from './types';
import { QUOTES, ANCIENT_QUOTES, COLORS, SUMI_COLORS, CONSTELLATIONS, HOLIDAYS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const [activeHoliday, setActiveHoliday] = useState<HolidayConfig | null>(null);
  const [showHolidaySplash, setShowHolidaySplash] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  const lastFireTime = useRef(0);
  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number, speed: number}[]>([]);
  const auroraWaves = useRef<{offset: number, speed: number, color: string}[]>([]);
  const requestRef = useRef<number>();

  // Online/Offline Listeners
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Check for Holiday on Mount
  useEffect(() => {
    const now = new Date();
    const holiday = HOLIDAYS.find(h => h.match(now));
    if (holiday) {
      setActiveHoliday(holiday);
      const storageKey = `holiday_splash_${holiday.id}_${now.getFullYear()}`;
      if (holiday.firstLaunchEffect && !localStorage.getItem(storageKey)) {
        setShowHolidaySplash(true);
        localStorage.setItem(storageKey, 'true');
        setTimeout(() => setShowHolidaySplash(false), 5000);
      }
    }
  }, []);

  // Initialize Elements
  useEffect(() => {
    // Stars
    const stars = [];
    for (let i = 0; i < 250; i++) {
      stars.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight * 0.8,
        s: Math.random() * 1.5,
        a: Math.random(),
        t: Math.random() * 100,
        speed: 0.01 + Math.random() * 0.02
      });
    }
    backgroundStars.current = stars;

    // Aurora Config
    auroraWaves.current = [
      { offset: 0, speed: 0.0004, color: 'rgba(0, 255, 150, 0.04)' },
      { offset: Math.PI / 2, speed: 0.0003, color: 'rgba(100, 0, 255, 0.03)' },
      { offset: Math.PI, speed: 0.0005, color: 'rgba(0, 200, 255, 0.03)' }
    ];
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 50 + 30);
    const layers = power > 2.2 ? 3 : (power > 1.2 ? 2 : 1);

    let particleColor: string;
    if (isOffline) {
      particleColor = SUMI_COLORS[Math.floor(Math.random() * SUMI_COLORS.length)];
    } else {
      const finalColors = (activeHoliday && Math.random() > 0.4) ? activeHoliday.specialColors : [color];
      particleColor = finalColors[Math.floor(Math.random() * finalColors.length)];
    }

    // Layer 1: Elegant Petal Burst
    const isSpecial = Math.random() > 0.85;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 2.5 + 2.5) * power;
      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: isOffline ? 1.8 : 1.2 + Math.random() * 0.8,
        color: particleColor,
        size: isOffline ? 3 + Math.random() * 5 : 1.5 + Math.random() * 1.5,
        friction: isOffline ? 0.93 : 0.965,
        gravity: isOffline ? 0.07 : 0.04,
        trail: [],
        shape: isSpecial ? (Math.random() > 0.5 ? 'star' : 'heart') : 'circle'
      };
      particles.current.push(p);
    }

    // Layer 2: Shimmering Dust
    if (layers >= 2) {
      const subCount = Math.floor(count * 0.6);
      for (let i = 0; i < subCount; i++) {
        const angle = Math.random() * Math.PI * 2;
        const speed = (Math.random() * 4 + 2) * power;
        const p: Particle = {
          x, y,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          life: 1,
          maxLife: 1.5,
          color: isOffline ? '#555555' : '#FFD700',
          size: 0.8,
          friction: 0.95,
          gravity: 0.06,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Surprise Constellation
    if (!isOffline && Math.random() > 0.92) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 25 * power;
      const rotation = Math.random() * Math.PI * 2;
      constellation.points.forEach(([px, py]) => {
        const cosR = Math.cos(rotation), sinR = Math.sin(rotation);
        const rx = px * cosR - py * sinR;
        const ry = px * sinR + py * cosR;
        particles.current.push({
          x: x + rx * scale, y: y + ry * scale,
          vx: (Math.random() - 0.5) * 0.1, vy: (Math.random() - 0.5) * 0.1,
          life: 1, maxLife: 4, color: '#FFFFFF', size: 2.2, friction: 0.98, gravity: 0, trail: []
        });
      });
    }

    // Quotes Logic
    const quotePool = isOffline ? ANCIENT_QUOTES : (activeHoliday ? activeHoliday.specialQuotes : QUOTES);
    const quote = quotePool[Math.floor(Math.random() * quotePool.length)];
    setBlessings(prev => [...prev.slice(-2), { text: quote, opacity: 1, y: y - 80, id: Date.now(), scale: 1 }]);

    audioService.playPop(power);
  }, [activeHoliday, isOffline]);

  const triggerGalaxyFall = useCallback((customColor?: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 120; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        particles.current.push({
          x: x, y: -20, vx: (Math.random() - 0.5) * 0.5, vy: Math.random() * 3 + 1.5,
          life: 1, maxLife: 5, color: customColor || (isOffline ? '#222222' : '#FFFFFF'),
          size: 1.2, friction: 0.995, gravity: 0.005, trail: []
        });
      }, i * 15);
    }
  }, [isOffline]);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    let color = isOffline ? '#000000' : COLORS[Math.floor(Math.random() * COLORS.length)];
    if (!isOffline && activeHoliday) color = activeHoliday.specialColors[0];

    projectiles.current.push({
      x: canvas.width / 2 + (Math.random() - 0.5) * 80,
      y: canvas.height + 20,
      targetY: y,
      vx: (x - canvas.width / 2) / 75,
      vy: -13 - power * 1.8,
      color, power, trail: [], active: true
    });

    audioService.playLaunch();
    const now = Date.now();
    if (now - lastFireTime.current < 2500) {
      setCombo(c => {
        const next = c + 1;
        if (next === 5) triggerGalaxyFall(activeHoliday?.specialColors[1]);
        return next;
      });
    } else setCombo(1);
    lastFireTime.current = now;
  }, [triggerGalaxyFall, activeHoliday, isOffline]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;
    ctx.clearRect(0, 0, width, height);

    if (isOffline) {
      ctx.fillStyle = '#f8f5f0'; // Aged silk parchment
      ctx.fillRect(0, 0, width, height);
      // Subtle paper texture
      ctx.fillStyle = 'rgba(0,0,0,0.015)';
      for(let i=0; i<300; i++) ctx.fillRect(Math.random()*width, Math.random()*height, 1, 1);
    } else {
      const bgGrad = ctx.createLinearGradient(0, 0, 0, height);
      bgGrad.addColorStop(0, '#010105');
      bgGrad.addColorStop(1, '#08081a');
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, width, height);

      // Aurora Silky Waves
      const now = Date.now();
      ctx.save();
      ctx.globalCompositeOperation = 'screen';
      auroraWaves.current.forEach(wave => {
        const grad = ctx.createLinearGradient(0, 0, width, 0);
        grad.addColorStop(0, 'transparent');
        grad.addColorStop(0.5, wave.color);
        grad.addColorStop(1, 'transparent');
        ctx.fillStyle = grad;

        ctx.beginPath();
        ctx.moveTo(0, height * 0.4);
        for (let x = 0; x <= width; x += 40) {
          const y = height * 0.25 + Math.sin(x * 0.0015 + now * wave.speed + wave.offset) * 80;
          ctx.lineTo(x, y);
        }
        ctx.lineTo(width, height);
        ctx.lineTo(0, height);
        ctx.fill();
      });
      ctx.restore();

      // Stars
      backgroundStars.current.forEach(s => {
        s.t += s.speed;
        const opacity = s.a * (0.3 + Math.sin(s.t) * 0.7);
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity})`;
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.s, 0, Math.PI * 2);
        ctx.fill();
        // Cross glow for bright stars
        if (s.s > 1.2 && opacity > 0.8) {
          ctx.strokeStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
          ctx.beginPath();
          ctx.moveTo(s.x - 3, s.y); ctx.lineTo(s.x + 3, s.y);
          ctx.moveTo(s.x, s.y - 3); ctx.lineTo(s.x, s.y + 3);
          ctx.stroke();
        }
      });
    }

    // Parallax Mountains
    const drawMountain = (h: number, c: string, parallax: number) => {
      ctx.fillStyle = c;
      ctx.beginPath();
      ctx.moveTo(0, height);
      for (let x = 0; x <= width; x += 100) {
        const yOffset = Math.sin(x * 0.001 * parallax) * 40;
        ctx.lineTo(x, height - h + yOffset);
      }
      ctx.lineTo(width, height);
      ctx.fill();
    };

    if (isOffline) {
      drawMountain(120, '#d1ccc0', 0.5);
      drawMountain(80, '#b8b3a9', 1.2);
    } else {
      drawMountain(150, '#010108', 0.5);
      drawMountain(100, '#030312', 1.1);
    }

    // Projectiles
    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx; p.y += p.vy; p.vy += 0.15;
      p.trail.push({ x: p.x, y: p.y });
      if (p.trail.length > 25) p.trail.shift();

      ctx.beginPath();
      ctx.strokeStyle = p.color;
      ctx.lineWidth = isOffline ? 3 : 1.5;
      ctx.lineCap = 'round';
      p.trail.forEach((pos, i) => {
        ctx.globalAlpha = i / p.trail.length;
        if (i === 0) ctx.moveTo(pos.x, pos.y); else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke();
      ctx.globalAlpha = 1;

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    // Particles
    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction; p.vy *= p.friction; p.vy += p.gravity;
      p.x += p.vx; p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = isOffline ? p.life * 0.7 : p.life;
        const s = Math.max(0.2, p.size * p.life);

        if (p.shape === 'star' && !isOffline) {
          ctx.beginPath();
          for(let i=0; i<5; i++) {
            const a = (Math.PI*2/5)*i - Math.PI/2;
            ctx.lineTo(p.x + Math.cos(a)*s*2, p.y + Math.sin(a)*s*2);
            ctx.lineTo(p.x + Math.cos(a + Math.PI/5)*s, p.y + Math.sin(a + Math.PI/5)*s);
          }
          ctx.closePath();
          ctx.fill();
        } else if (p.shape === 'heart' && !isOffline) {
          ctx.beginPath();
          ctx.moveTo(p.x, p.y);
          ctx.bezierCurveTo(p.x - s*2, p.y - s*3, p.x - s*4, p.y + s, p.x, p.y + s*4);
          ctx.bezierCurveTo(p.x + s*4, p.y + s, p.x + s*2, p.y - s*3, p.x, p.y);
          ctx.fill();
        } else {
          ctx.beginPath();
          ctx.arc(p.x, p.y, s, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    });
    ctx.globalAlpha = 1;

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles, isOffline]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    window.addEventListener('resize', resize);
    resize();
    requestRef.current = requestAnimationFrame(() => update(ctx));
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); window.removeEventListener('resize', resize); };
  }, [update]);

  // Charging Animation
  useEffect(() => {
    let timer: number;
    if (charging) timer = window.setInterval(() => setChargeLevel(p => Math.min(p + 0.04, 3)), 30);
    return () => clearInterval(timer);
  }, [charging]);

  const handleStart = (e: any) => { e.preventDefault(); setCharging(true); setChargeLevel(0.4); };
  const handleEnd = (e: any) => {
    if (!charging) return;
    e.preventDefault();
    setCharging(false);
    const pos = (e.touches ? e.changedTouches[0] : e);
    launchFirework(pos.clientX, pos.clientY, chargeLevel);
    setChargeLevel(0);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      setBlessings(prev => prev.map(b => ({
        ...b, y: b.y - (isOffline ? 0.2 : 0.4), opacity: b.opacity - 0.003
      })).filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(timer);
  }, [isOffline]);

  return (
    <div 
      className={`relative w-full h-screen overflow-hidden touch-none transition-all duration-1000 ${isOffline ? 'bg-[#f8f5f0]' : 'bg-[#020205]'}`}
      onMouseDown={handleStart} onMouseUp={handleEnd} onTouchStart={handleStart} onTouchEnd={handleEnd}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      {/* Holiday Splash Overlay */}
      {showHolidaySplash && !isOffline && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-[#4a0000]/90 transition-opacity duration-1000 animate-pulse pointer-events-none">
          <div className="text-center">
            <h2 className="text-[#D4AF37] font-poetic text-8xl drop-shadow-2xl animate-poetic-entry">春节快乐</h2>
            <div className="mt-8 text-white/40 font-serif-elegant text-xl tracking-[0.5em] uppercase">Spring Festival Bliss</div>
          </div>
        </div>
      )}

      {/* Top Header */}
      <div className="absolute top-12 left-0 right-0 pointer-events-none flex flex-col items-center select-none">
        <h1 className={`text-2xl font-serif-elegant tracking-[0.4em] opacity-40 mb-1 transition-colors duration-1000 ${isOffline ? 'text-[#0a0a0a]' : 'text-white'}`}>
          {isOffline ? '墨 · 染' : '星 愿 · 夜 穹'}
        </h1>
        <div className={`h-[1px] w-12 transition-colors duration-1000 ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}></div>
      </div>

      {/* Charge Indicator */}
      {charging && (
        <div className="absolute bottom-16 left-1/2 -translate-x-1/2 w-40 flex flex-col items-center gap-2">
          <div className={`h-[1px] w-full relative overflow-hidden transition-colors ${isOffline ? 'bg-black/5' : 'bg-white/5'}`}>
            <div 
              className={`h-full absolute left-0 transition-all duration-75 ${isOffline ? 'bg-black' : 'bg-white'}`}
              style={{ width: `${(chargeLevel / 3) * 100}%` }}
            />
          </div>
          <span className={`text-[9px] tracking-[0.3em] font-serif-elegant uppercase ${isOffline ? 'text-black/40' : 'text-white/40'}`}>Charging Wish</span>
        </div>
      )}

      {/* Combo Indicator */}
      {combo > 1 && (
        <div className="absolute top-32 left-1/2 -translate-x-1/2 pointer-events-none">
          <span className={`font-serif-elegant text-sm italic transition-colors ${isOffline ? 'text-[#8B0000]' : 'text-[#D4AF37]'}`}>
            {combo}x Sequence
          </span>
        </div>
      )}

      {/* Blessings */}
      {blessings.map(b => (
        <div 
          key={b.id}
          className={`absolute left-1/2 -translate-x-1/2 pointer-events-none font-serif-elegant text-xl whitespace-nowrap transition-all duration-1000`}
          style={{ 
            top: `${b.y}px`, 
            opacity: b.opacity,
            color: isOffline ? '#000000' : '#f0f0f0',
            letterSpacing: '0.4em',
            writingMode: isOffline ? 'vertical-rl' : 'horizontal-tb'
          }}
        >
          {b.text}
        </div>
      ))}

      {/* Footer Info */}
      <div className={`absolute bottom-6 right-8 text-[9px] tracking-[0.2em] font-serif-elegant pointer-events-none transition-colors duration-1000 uppercase ${isOffline ? 'text-black/20' : 'text-white/20'}`}>
        {isOffline ? 'Offline Mode' : (activeHoliday ? `Observed: ${activeHoliday.name}` : 'Midnight Serenade')}
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point, HolidayConfig } from './types';
import { QUOTES, ANCIENT_QUOTES, COLORS, SUMI_COLORS, CONSTELLATIONS, HOLIDAYS } from './constants';
