        setTimeout(() => setShowHolidaySplash(false), 5000);
      }
    }
  }, []);

  // Background Elements Init
  useEffect(() => {
    const initElements = () => {
      const w = window.innerWidth;
      const h = window.innerHeight;

      const stars = [];
      for (let i = 0; i < 300; i++) {
        stars.push({
          x: Math.random() * w,
