        if (p.shape === 'star' && !isOffline) {
          ctx.beginPath(); for(let i=0; i<5; i++) {
            const a = (Math.PI*2/5)*i - Math.PI/2;
            ctx.lineTo(p.x+Math.cos(a)*s*2.2, p.y+Math.sin(a)*s*2.2);
            ctx.lineTo(p.x+Math.cos(a+Math.PI/5)*s*0.9, p.y+Math.sin(a+Math.PI/5)*s*0.9);
          }
          ctx.closePath(); ctx.fill();
        } else if (p.shape === 'heart' && !isOffline) {
          ctx.beginPath(); ctx.moveTo(p.x, p.y);
          ctx.bezierCurveTo(p.x-s*2, p.y-s*3, p.x-s*4, p.y+s, p.x, p.y+s*4);
          ctx.bezierCurveTo(p.x+s*4, p.y+s, p.x+s*2, p.y-s*3, p.x, p.y); ctx.fill();
        } else {
          ctx.beginPath(); ctx.arc(p.x, p.y, s, 0, Math.PI * 2); ctx.fill();
        }
      }
    });
    ctx.globalAlpha = 1;
    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles, isOffline]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Resize handler using visual viewport if available, else standard inner dimensions
    const resize = () => { 
      const w = window.visualViewport ? window.visualViewport.width : window.innerWidth;
      const h = window.visualViewport ? window.visualViewport.height : window.innerHeight;
      canvas.width = w; 
      canvas.height = h; 
    };

    if (window.visualViewport) {
      window.visualViewport.addEventListener('resize', resize);
    }
    window.addEventListener('resize', resize); 
    resize();

    requestRef.current = requestAnimationFrame(() => update(ctx));
    return () => { 
      if (requestRef.current) cancelAnimationFrame(requestRef.current); 
      window.removeEventListener('resize', resize);
      if (window.visualViewport) {
        window.visualViewport.removeEventListener('resize', resize);
      }
    };
  }, [update]);

  useEffect(() => {
    let t: number;
    if (charging) t = window.setInterval(() => setChargeLevel(p => Math.min(p + 0.045, 3)), 30);
    return () => clearInterval(t);
  }, [charging]);

  const onStart = (e: any) => { setCharging(true); setChargeLevel(0.4); };
  const onEnd = (e: any) => {
    if (!charging) return; setCharging(false);
    const pos = (e.touches ? e.changedTouches[0] : e);
    launchFirework(pos.clientX, pos.clientY, chargeLevel); setChargeLevel(0);
  };

  useEffect(() => {
    const t = setInterval(() => {
      setBlessings(prev => prev.map(b => ({ ...b, y: b.y - (isOffline ? 0.3 : 0.5), opacity: b.opacity - 0.0035 }))
        .filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(t);
  }, [isOffline]);

  return (
    <div 
      className={`fixed inset-0 overflow-hidden touch-none transition-all duration-1000 ${isOffline ? 'bg-[#fdfbf7]' : 'bg-[#020205]'}`}
      onMouseDown={onStart} onMouseUp={onEnd} onTouchStart={onStart} onTouchEnd={onEnd}
    >
      <canvas ref={canvasRef} className="absolute inset-0 z-0 block" />
      {showHolidaySplash && !isOffline && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-[#400]/90 animate-pulse pointer-events-none">
          <div className="text-center">
            <h2 className="text-[#D4AF37] font-poetic text-8xl drop-shadow-2xl animate-poetic-entry">春节快乐</h2>
            <div className="mt-6 text-white/30 font-serif-elegant text-lg tracking-[0.6em] uppercase">Season of Blossom</div>
          </div>
        </div>
      )}
      <div className="absolute top-16 left-0 right-0 pointer-events-none flex flex-col items-center select-none z-10">
        <h1 className={`text-2xl font-serif-elegant tracking-[0.5em] opacity-40 mb-2 transition-colors duration-1000 ${isOffline ? 'text-black' : 'text-white'}`}>
          {isOffline ? '墨 · 染' : '星 愿 · 夜 穹'}
        </h1>
        <div className={`h-[1px] w-14 transition-colors duration-1000 ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}></div>
      </div>
      {charging && (
        <div className="absolute bottom-20 left-1/2 -translate-x-1/2 w-44 flex flex-col items-center gap-2 z-10">
          <div className={`h-[1px] w-full relative overflow-hidden ${isOffline ? 'bg-black/5' : 'bg-white/5'}`}>
            <div className={`h-full absolute left-0 ${isOffline ? 'bg-black' : 'bg-white'}`} style={{ width: `${(chargeLevel/3)*100}%` }} />
          </div>
          <span className={`text-[8px] tracking-[0.4em] font-serif-elegant uppercase ${isOffline ? 'text-black/40' : 'text-white/40'}`}>Gilding The Night</span>
        </div>
      )}
      {combo > 1 && (
        <div className="absolute top-40 left-1/2 -translate-x-1/2 z-10">
          <span className={`font-serif-elegant text-xs italic tracking-widest ${isOffline ? 'text-[#800]' : 'text-[#D4AF37]'}`}>{combo}x Harmony</span>
        </div>
      )}
      {blessings.map(b => (
        <div key={b.id} className="absolute left-1/2 -translate-x-1/2 pointer-events-none font-serif-elegant text-2xl whitespace-nowrap z-10"
          style={{ top: `${b.y}px`, opacity: b.opacity, color: isOffline ? '#000' : '#fff', letterSpacing: '0.5em', writingMode: isOffline ? 'vertical-rl' : 'horizontal-tb' }}>
          {b.text}
        </div>
      ))}
      <div className={`absolute bottom-8 right-10 text-[8px] tracking-[0.3em] font-serif-elegant pointer-events-none z-10 uppercase ${isOffline ? 'text-black/20' : 'text-white/20'}`}>
        {isOffline ? 'Paper & Ink' : (activeHoliday ? `Event: ${activeHoliday.name}` : 'Eternal Starlight')}
      </div>
    </div>
  );
};

