    if (holiday) {
      setActiveHoliday(holiday);
      const storageKey = `holiday_splash_${holiday.id}_${now.getFullYear()}`;
      if (holiday.firstLaunchEffect && !localStorage.getItem(storageKey)) {
        setShowHolidaySplash(true);
        localStorage.setItem(storageKey, 'true');
        setTimeout(() => setShowHolidaySplash(false), 5000);
      }
    }
  }, []);

  // Background Elements Init
  useEffect(() => {
    const initElements = () => {
      const w = window.innerWidth;
      const h = window.innerHeight;
      const stars = [];
      for (let i = 0; i < 300; i++) {
        stars.push({
          x: Math.random() * w,
          y: Math.random() * h,
          s: Math.random() * 1.5,
          a: Math.random(),
          t: Math.random() * 100,
          speed: 0.01 + Math.random() * 0.02
        });
      }
      backgroundStars.current = stars;
    };

    initElements();
    auroraWaves.current = [
      { offset: 0, speed: 0.0004, color: 'rgba(0, 255, 150, 0.05)' },
      { offset: Math.PI / 2, speed: 0.0003, color: 'rgba(100, 0, 255, 0.04)' },
      { offset: Math.PI, speed: 0.0005, color: 'rgba(0, 200, 255, 0.04)' }
    ];

    window.addEventListener('resize', initElements);
    return () => window.removeEventListener('resize', initElements);
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 55 + 35);
    let particleColor: string;
    if (isOffline) {
      particleColor = SUMI_COLORS[Math.floor(Math.random() * SUMI_COLORS.length)];
    } else {
      const finalColors = (activeHoliday && Math.random() > 0.4) ? activeHoliday.specialColors : [color];
      particleColor = finalColors[Math.floor(Math.random() * finalColors.length)];
    }

    const isSpecial = Math.random() > 0.88;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 2.5 + 2.8) * power;
      particles.current.push({
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: isOffline ? 2.2 : 1.3 + Math.random() * 0.9,
        color: particleColor,
        size: isOffline ? 4 + Math.random() * 6 : 1.6 + Math.random() * 1.6,
        friction: isOffline ? 0.92 : 0.965,
        gravity: isOffline ? 0.08 : 0.045,
        trail: [],
        shape: isSpecial ? (Math.random() > 0.5 ? 'star' : 'heart') : 'circle'
      });
    }

    if (!isOffline && Math.random() > 0.93) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 30 * power;
      const rotation = Math.random() * Math.PI * 2;
      constellation.points.forEach(([px, py]) => {
        const cosR = Math.cos(rotation), sinR = Math.sin(rotation);
        particles.current.push({
          x: x + (px * cosR - py * sinR) * scale,
          y: y + (px * sinR + py * cosR) * scale,
          vx: 0, vy: 0, life: 1, maxLife: 3.5, color: '#FFFFFF', size: 2.5, friction: 0.99, gravity: 0, trail: []
        });
      });
    }

    const pool = isOffline ? ANCIENT_QUOTES : (activeHoliday ? activeHoliday.specialQuotes : QUOTES);
    const quote = pool[Math.floor(Math.random() * pool.length)];
    setBlessings(prev => [...prev.slice(-2), { text: quote, opacity: 1, y: y - 100, id: Date.now(), scale: 1 }]);
    audioService.playPop(power);
  }, [activeHoliday, isOffline]);

  const triggerGalaxyFall = useCallback((customColor?: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 150; i++) {
      setTimeout(() => {
        particles.current.push({
          x: Math.random() * canvas.width, y: -20, vx: (Math.random() - 0.5) * 0.5, vy: Math.random() * 3 + 2,
          life: 1, maxLife: 5, color: customColor || (isOffline ? '#1a1a1a' : '#FFFFFF'),
          size: 1.2, friction: 0.99, gravity: 0.01, trail: []
        });
      }, i * 15);
    }
  }, [isOffline]);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    let color = isOffline ? '#000000' : (activeHoliday ? activeHoliday.specialColors[0] : COLORS[Math.floor(Math.random() * COLORS.length)]);
    projectiles.current.push({
      x: canvas.width / 2 + (Math.random() - 0.5) * 100, y: canvas.height + 20, targetY: y,
      vx: (x - canvas.width / 2) / 70, vy: -13 - power * 2, color, power, trail: [], active: true
    });
    audioService.playLaunch();
    const now = Date.now();
    if (now - lastFireTime.current < 2500) {
      setCombo(c => {
        const n = c + 1;
        if (n === 5) triggerGalaxyFall(activeHoliday?.specialColors[1]);
        return n;
      });
    } else setCombo(1);
    lastFireTime.current = now;
  }, [triggerGalaxyFall, activeHoliday, isOffline]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;
    ctx.clearRect(0, 0, width, height);

    // Background Gradient with massive overdraw to fix mobile gaps
    if (isOffline) {
      ctx.fillStyle = '#fdfbf7';
      ctx.fillRect(-100, -100, width + 200, height + 400);
    } else {
      const bg = ctx.createLinearGradient(0, 0, 0, height);
      bg.addColorStop(0, '#020208');
      bg.addColorStop(1, '#08081a');
      ctx.fillStyle = bg;
      ctx.fillRect(-100, -100, width + 200, height + 400);

      const now = Date.now();
      ctx.save();
      ctx.globalCompositeOperation = 'screen';
      auroraWaves.current.forEach(w => {
        const g = ctx.createLinearGradient(0, 0, width, 0);
        g.addColorStop(0, 'transparent'); g.addColorStop(0.5, w.color); g.addColorStop(1, 'transparent');
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.moveTo(-50, height * 0.4);
        for (let x = -50; x <= width + 50; x += 30) {
          ctx.lineTo(x, height * 0.25 + Math.sin(x * 0.0012 + now * w.speed + w.offset) * 70);
        }
        ctx.lineTo(width + 50, height + 400); ctx.lineTo(-50, height + 400);
        ctx.fill();
      });
      ctx.restore();

      backgroundStars.current.forEach(s => {
        s.t += s.speed;
        const o = s.a * (0.2 + Math.sin(s.t) * 0.8);
        ctx.fillStyle = `rgba(255, 255, 255, ${o})`;
        ctx.beginPath(); ctx.arc(s.x, s.y, s.s, 0, Math.PI * 2); ctx.fill();
      });
    }

    // Extended mountain drawing to ensure no bottom gaps
    const drawM = (h: number, c: string, p: number) => {
      ctx.fillStyle = c; 
      ctx.beginPath(); 
      ctx.moveTo(-100, height + 400);
      ctx.lineTo(-100, height);
      for (let x = -50; x <= width + 50; x += 80) {
        ctx.lineTo(x, height - h + Math.sin(x * 0.0008 * p) * 35);
      }
      ctx.lineTo(width + 100, height);
      ctx.lineTo(width + 100, height + 400);
      ctx.closePath();
      ctx.fill();
    };

    if (isOffline) {
      drawM(140, '#e5e0d4', 0.6); drawM(90, '#d8d3c5', 1.3);
    } else {
      drawM(160, '#010107', 0.4); drawM(110, '#03030d', 1.2);
    }

    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx; p.y += p.vy; p.vy += 0.16;
      p.trail.push({ x: p.x, y: p.y }); if (p.trail.length > 25) p.trail.shift();
      ctx.beginPath(); ctx.strokeStyle = p.color; ctx.lineWidth = isOffline ? 4 : 2; ctx.lineCap = 'round';
      p.trail.forEach((pos, i) => { ctx.globalAlpha = i/p.trail.length; if(i===0) ctx.moveTo(pos.x, pos.y); else ctx.lineTo(pos.x, pos.y); });
      ctx.stroke(); ctx.globalAlpha = 1;
      if (p.vy >= 0 || p.y <= p.targetY) { p.active = false; createParticles(p.x, p.y, p.color, p.power); }
    });

    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction; p.vy *= p.friction; p.vy += p.gravity; p.x += p.vx; p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);
      if (p.life > 0) {
        ctx.fillStyle = p.color; ctx.globalAlpha = isOffline ? p.life * 0.8 : p.life;
        const s = Math.max(0.1, p.size * p.life);
        ctx.beginPath(); ctx.arc(p.x, p.y, s, 0, Math.PI * 2); ctx.fill();
      }
    });
    ctx.globalAlpha = 1;
    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles, isOffline]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Use innerHeight for reliable fullscreen coverage on mobile
    const resize = () => { 
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize); 
    resize();

    requestRef.current = requestAnimationFrame(() => update(ctx));
    return () => { 
      if (requestRef.current) cancelAnimationFrame(requestRef.current); 
      window.removeEventListener('resize', resize);
    };
  }, [update]);

  // Optimized pointer handling to prevent "stuck" state
  const startCharge = (e: React.PointerEvent) => {
    if (isChargingRef.current) return;

    // Capture pointer to ensure we get the up event even if cursor leaves
    (e.target as Element).setPointerCapture(e.pointerId);

    isChargingRef.current = true;
    setCharging(true);
    setChargeLevel(0.4);
    chargeLevelRef.current = 0.4;

    timerRef.current = window.setInterval(() => {
      setChargeLevel(prev => {
        const next = Math.min(prev + 0.045, 3);
        chargeLevelRef.current = next; // Update ref for immediate access
        return next;
      });
    }, 30);
  };

  const endCharge = (e: React.PointerEvent) => {
    if (!isChargingRef.current) return;

    if (timerRef.current) {
      clearInterval(timerRef.current);
    }

    isChargingRef.current = false;
    setCharging(false);
    launchFirework(e.clientX, e.clientY, chargeLevelRef.current);

    // Reset levels
    setChargeLevel(0);
    chargeLevelRef.current = 0;
  };

  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    const t = setInterval(() => {
      setBlessings(prev => prev.map(b => ({ ...b, y: b.y - (isOffline ? 0.3 : 0.5), opacity: b.opacity - 0.0035 }))
        .filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(t);
  }, [isOffline]);

  return (
    <div 
      className={`fixed inset-0 overflow-hidden touch-none transition-all duration-1000 ${isOffline ? 'bg-[#fdfbf7]' : 'bg-[#020205]'}`}
      onPointerDown={startCharge}
      onPointerUp={endCharge}
      onPointerCancel={endCharge} // Handle cancellations (e.g. system interruptions)
    >
      <canvas ref={canvasRef} className="absolute inset-0 z-0 block" />
      {showHolidaySplash && !isOffline && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-[#400]/90 pointer-events-none">
          <div className="text-center">
            <h2 className="text-[#D4AF37] font-poetic text-8xl animate-poetic-entry">春节快乐</h2>
          </div>
        </div>
      )}
      <div className="absolute top-16 left-0 right-0 pointer-events-none flex flex-col items-center select-none z-10">
        <h1 className={`text-2xl font-serif-elegant tracking-[0.5em] opacity-40 mb-2 transition-colors duration-1000 ${isOffline ? 'text-black' : 'text-white'}`}>
          {isOffline ? '墨 · 染' : '星 愿 · 夜 穹'}
        </h1>
        <div className={`h-[1px] w-14 transition-colors duration-1000 ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}></div>
      </div>

      <div className={`absolute bottom-20 left-1/2 -translate-x-1/2 w-44 flex flex-col items-center gap-2 z-20 transition-opacity duration-300 ${charging ? 'opacity-100' : 'opacity-0'}`}>
        <div className={`h-[1px] w-full relative overflow-hidden ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}>
          <div className={`h-full absolute left-0 transition-all duration-75 ${isOffline ? 'bg-black' : 'bg-white'}`} style={{ width: `${(chargeLevel/3)*100}%` }} />
        </div>
        <span className={`text-[8px] tracking-[0.4em] font-serif-elegant uppercase ${isOffline ? 'text-black/40' : 'text-white/40'}`}>Gilding The Night</span>
      </div>

      {combo > 1 && (
        <div className="absolute top-40 left-1/2 -translate-x-1/2 z-10">
          <span className={`font-serif-elegant text-xs italic tracking-widest ${isOffline ? 'text-[#800]' : 'text-[#D4AF37]'}`}>{combo}x Harmony</span>
        </div>
      )}

      {blessings.map(b => (
        <div key={b.id} className="absolute left-1/2 -translate-x-1/2 pointer-events-none font-serif-elegant text-2xl whitespace-nowrap z-10"
          style={{ top: `${b.y}px`, opacity: b.opacity, color: isOffline ? '#000' : '#fff', letterSpacing: '0.5em' }}>
          {b.text}
        </div>
      ))}
      <div className={`absolute bottom-8 right-10 text-[8px] tracking-[0.3em] font-serif-elegant pointer-events-none z-10 uppercase ${isOffline ? 'text-black/20' : 'text-white/20'}`}>
        {isOffline ? 'Paper & Ink' : (activeHoliday ? `Event: ${activeHoliday.name}` : 'Eternal Starlight')}
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point } from './types';
import { QUOTES, COLORS, CONSTELLATIONS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const lastFireTime = useRef(0);

  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number}[]>([]);
  const requestRef = useRef<number>();

  // Initialize Stars
  useEffect(() => {
    const stars = [];
    for (let i = 0; i < 200; i++) {
      stars.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight * 0.7,
        s: Math.random() * 2,
        a: Math.random(),
        t: Math.random() * 100
      });
    }
    backgroundStars.current = stars;
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 50 + 30);
    const layers = power > 2.5 ? 3 : (power > 1.5 ? 2 : 1);

    // Layer 1: Core Burst
    const isSpecial = Math.random() > 0.9;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      // Increased initial speed for more explosive feel
      const speed = (Math.random() * 3.5 + 3) * power;
      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: 0.8 + Math.random() * 0.6,
        color,
        size: 2.5 + Math.random() * 2,
        // Tuned physics: Higher drag (0.95) and realistic gravity (0.2)
        friction: 0.95,
        gravity: 0.2,
        trail: [],
        shape: isSpecial ? 'star' : 'circle'
      };
      particles.current.push(p);
    }

    // Layer 2: Secondary Ring / Sparkles
    if (layers >= 2) {
      const subCount = count * 0.8;
      for (let i = 0; i < subCount; i++) {
        const angle = (Math.PI * 2 / subCount) * i;
        const speed = (Math.random() * 2 + 5) * power;
        const p: Particle = {
          x, y,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          life: 1,
          maxLife: 1.2,
          color: '#FFFFFF', 
          size: 1.8,
          // Lighter particles, slightly more drag, less gravity
          friction: 0.93,
          gravity: 0.15,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Layer 3: Falling Dust / Smoke
    if (layers >= 3) {
      for (let i = 0; i < 60; i++) {
        const p: Particle = {
          x: x + (Math.random() - 0.5) * 50,
          y: y + (Math.random() - 0.5) * 50,
          vx: (Math.random() - 0.5) * 3,
          vy: (Math.random() - 0.5) * 3,
          life: 1,
          maxLife: 2.0 + Math.random(),
          color: `rgba(255, 255, 255, 0.6)`,
          size: 1.2,
          // High drag (air resistance), low gravity for floating effect
          friction: 0.9,
          gravity: 0.05,
          trail: []
        };
        particles.current.push(p);
      }
    }

    // Surprise: Constellation pattern
    if (Math.random() > 0.92) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 35 * power;
      const rotation = Math.random() * Math.PI * 2;
      const cosR = Math.cos(rotation);
      const sinR = Math.sin(rotation);

      constellation.points.forEach(([px, py]) => {
        // Rotate and scale
        const rx = px * cosR - py * sinR;
        const ry = px * sinR + py * cosR;
        const p: Particle = {
          x: x + rx * scale,
          y: y + ry * scale,
          vx: 0,
          vy: 0,
          life: 1,
          maxLife: 3.5,
          color: '#ADD8E6',
          size: 3,
          friction: 0.98, // Keep shape longer
          gravity: 0.02,  // Slowly drift
          trail: []
        };
        particles.current.push(p);
      });
    }

    // Add Blessing Text
    const quote = QUOTES[Math.floor(Math.random() * QUOTES.length)];
    setBlessings(prev => [...prev.slice(-3), { text: quote, opacity: 1, y: y - 50, id: Date.now() }]);

    audioService.playPop(power);
  }, []);

  const triggerGalaxyFall = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 120; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        const p: Particle = {
          x: x,
          y: -20,
          vx: (Math.random() - 0.5) * 0.5,
          vy: Math.random() * 4 + 2,
          life: 1,
          maxLife: 5,
          color: '#E0F0FF',
          size: 1.5,
          friction: 0.99,
          gravity: 0.01,
          trail: []
        };
        particles.current.push(p);
      }, i * 15);
    }
  }, []);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const color = COLORS[Math.floor(Math.random() * COLORS.length)];
    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 100,
      y: canvas.height + 20, // Start slightly off screen
      targetY: y,
      vx: (x - canvas.width / 2) / 65,
      vy: -14 - power * 2, // Adjusted launch speed
      color,
      power,
      trail: [],
      active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    // Combo Logic
    const now = Date.now();
    if (now - lastFireTime.current < 2500) { // Slightly tighter combo window
      setCombo(c => {
        const next = c + 1;
        if (next === 5) triggerGalaxyFall();
        return next;
      });
    } else {
      setCombo(1);
    }
    lastFireTime.current = now;
  }, [triggerGalaxyFall]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;

    // Background Gradient
    const grad = ctx.createLinearGradient(0, 0, 0, height);
    grad.addColorStop(0, '#02020a');
    grad.addColorStop(0.5, '#050518');
    grad.addColorStop(1, '#0c0c28');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, width, height);

    // Draw Aurora
    const time = Date.now() / 2000;
    ctx.save();
    ctx.globalCompositeOperation = 'lighter';
    for (let i = 0; i < 3; i++) {
      const aGrad = ctx.createLinearGradient(0, 0, width, 0);
      aGrad.addColorStop(0, 'rgba(0, 255, 128, 0)');
      aGrad.addColorStop(0.5, `rgba(0, 255, ${150 + i * 30}, 0.03)`);
      aGrad.addColorStop(1, 'rgba(255, 100, 255, 0)');
      ctx.fillStyle = aGrad;
      ctx.beginPath();
      ctx.moveTo(0, height * 0.3);
      for (let x = 0; x < width; x += 50) {
        const offset = Math.sin(x * 0.002 + time + i) * 100;
        ctx.lineTo(x, height * 0.2 + offset);
      }
      ctx.lineTo(width, height);
      ctx.lineTo(0, height);
      ctx.fill();
    }
    ctx.restore();

    // Draw Stars
    backgroundStars.current.forEach(star => {
      star.t += 0.02;
      const alpha = star.a * (0.5 + Math.sin(star.t) * 0.5);
      ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
      ctx.beginPath();
      ctx.arc(star.x, star.y, star.s, 0, Math.PI * 2);
      ctx.fill();
    });

    // Draw Mountains Silhouette
    ctx.fillStyle = '#020208';
    ctx.beginPath();
    ctx.moveTo(0, height);
    ctx.lineTo(0, height - 100);
    ctx.quadraticCurveTo(width * 0.25, height - 180, width * 0.5, height - 120);
    ctx.quadraticCurveTo(width * 0.75, height - 200, width, height - 80);
    ctx.lineTo(width, height);
    ctx.fill();

    // Draw Moonlight Glow on Mountain
    const moonGlow = ctx.createRadialGradient(width/2, height, 0, width/2, height, height);
    moonGlow.addColorStop(0, 'rgba(100, 100, 255, 0.1)');
    moonGlow.addColorStop(1, 'rgba(0, 0, 0, 0)');
    ctx.fillStyle = moonGlow;
    ctx.fillRect(0, height - 250, width, 250);

    // Update Projectiles
    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += 0.16; // Gravity on projectile

      p.trail.push({ x: p.x, y: p.y });
      if (p.trail.length > 25) p.trail.shift();

      ctx.beginPath();
      ctx.strokeStyle = p.color;
      ctx.lineWidth = 2;
      ctx.lineCap = 'round';

      p.trail.forEach((pos, idx) => {
         // Fade trail tail
        ctx.globalAlpha = idx / p.trail.length;
        if (idx === 0) ctx.moveTo(pos.x, pos.y);
        else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke();
      ctx.globalAlpha = 1;

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    // Update Particles
    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      // Physics Update
      p.vx *= p.friction;
      p.vy *= p.friction;
      p.vy += p.gravity;
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        // Non-linear fade: keeps brightness longer then fades out
        ctx.globalAlpha = Math.pow(p.life, 1.5); 

        if (p.shape === 'star') {
          const r = p.size;
          ctx.beginPath();
          for(let i=0; i<5; i++) {
            const a = (Math.PI*2/5)*i - Math.PI/2;
            const x = p.x + Math.cos(a)*r*1.5;
            const y = p.y + Math.sin(a)*r*1.5;
            if(i===0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
            const a2 = a + Math.PI/5;
            ctx.lineTo(p.x + Math.cos(a2)*r*0.6, p.y + Math.sin(a2)*r*0.6);
          }
          ctx.closePath();
          ctx.fill();
        } else {
          ctx.beginPath();
          // Size shrinks slightly as it dies
          const currentSize = Math.max(0.1, p.size * (0.5 + 0.5 * p.life));
          ctx.arc(p.x, p.y, currentSize, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    });
    ctx.globalAlpha = 1;

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    requestRef.current = requestAnimationFrame(() => update(ctx));

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', resize);
    };
  }, [update]);

  useEffect(() => {
    let timer: number;
    if (charging) {
      timer = window.setInterval(() => {
        setChargeLevel(prev => Math.min(prev + 0.045, 3));
      }, 30);
    }
    return () => clearInterval(timer);
  }, [charging]);

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    setCharging(true);
    setChargeLevel(0.4);
  };

  const handleMouseUp = (e: any) => {
    if (!charging) return;
    setCharging(false);
    const clientX = e.clientX || (e.changedTouches && e.changedTouches[0].clientX);
    const clientY = e.clientY || (e.changedTouches && e.changedTouches[0].clientY);
    launchFirework(clientX, clientY, chargeLevel);
    setChargeLevel(0);
  };

  // Update Blessings Animation
  useEffect(() => {
    const timer = setInterval(() => {
      setBlessings(prev => prev.map(b => ({
        ...b,
        y: b.y - 0.5,
        opacity: b.opacity - 0.0035 // Slower fade for text
      })).filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(timer);
  }, []);

  return (
    <div 
      className="relative w-full h-screen overflow-hidden"
      onMouseDown={handleMouseDown}
      onMouseUp={handleMouseUp}
      onTouchStart={handleMouseDown}
      onTouchEnd={handleMouseUp}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      {/* UI Overlay */}
      <div className="absolute top-8 left-0 right-0 pointer-events-none flex flex-col items-center select-none">
        <h1 className="text-white text-3xl font-poetic tracking-widest opacity-80 mb-2 drop-shadow-lg">星愿·夜穹</h1>
        <p className="text-blue-200/50 text-xs tracking-tighter">长按蓄力 • 释放心愿</p>
      </div>

      {/* Charge Bar */}
      {charging && (
        <div className="absolute bottom-20 left-1/2 -translate-x-1/2 w-48 h-1 bg-white/10 rounded-full overflow-hidden transition-opacity duration-300">
          <div 
            className="h-full bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400"
            style={{ width: `${(chargeLevel / 3) * 100}%` }}
          />
        </div>
      )}

      {/* Combo Badge */}
      {combo > 1 && (
        <div className="absolute top-24 left-1/2 -translate-x-1/2 animate-bounce pointer-events-none">
          <span className="text-yellow-300 font-bold text-xl drop-shadow-[0_0_10px_rgba(255,255,0,0.5)]">
            {combo}连绽!
          </span>
        </div>
      )}

      {/* Floating Blessings */}
      {blessings.map(b => (
        <div 
          key={b.id}
          className="absolute left-1/2 -translate-x-1/2 pointer-events-none font-poetic text-white text-2xl whitespace-nowrap drop-shadow-[0_0_8px_rgba(255,255,255,0.8)]"
          style={{ top: `${b.y}px`, opacity: b.opacity }}
        >
          {b.text}
        </div>
      ))}

      {/* Footer Info */}
      <div className="absolute bottom-4 right-6 text-white/30 text-[10px] pointer-events-none select-none">
        {new Date().getHours() >= 23 || new Date().getHours() < 1 ? '午夜特典：星尘入梦' : '当前：寂静深夜'}
      </div>
    </div>
  );
};

export default App;

