    specialColors: ['#FFB6C1', '#FF69B4', '#FF1493', '#FFFFFF'],
    specialQuotes: ["斯人若彩虹，遇上方知有", "宇宙山河浪漫，人间点滴温暖", "爱意东升西落，浪漫至死不渝"]
