import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point, HolidayConfig } from './types';
import { QUOTES, ANCIENT_QUOTES, COLORS, SUMI_COLORS, CONSTELLATIONS, HOLIDAYS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const [activeHoliday, setActiveHoliday] = useState<HolidayConfig | null>(null);
  const [showHolidaySplash, setShowHolidaySplash] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  const lastFireTime = useRef(0);
  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number, speed: number}[]>([]);
  const auroraWaves = useRef<{offset: number, speed: number, color: string}[]>([]);
  const requestRef = useRef<number>();

  // Connectivity Sync
  useEffect(() => {
    const syncOnline = () => setIsOffline(false);
    const syncOffline = () => setIsOffline(true);
    window.addEventListener('online', syncOnline);
    window.addEventListener('offline', syncOffline);
    return () => {
      window.removeEventListener('online', syncOnline);
      window.removeEventListener('offline', syncOffline);
    };
  }, []);

  // Holiday Sync
  useEffect(() => {
    const now = new Date();
    const holiday = HOLIDAYS.find(h => h.match(now));
    if (holiday) {
      setActiveHoliday(holiday);
      // Check if splashed today
      const storageKey = `holiday_splash_${holiday.id}_${now.getFullYear()}`;
      if (holiday.firstLaunchEffect && !localStorage.getItem(storageKey)) {
        setShowHolidaySplash(true);
        localStorage.setItem(storageKey, 'true');
        setTimeout(() => setShowHolidaySplash(false), 5000);
      }
    }
  }, []);

  // Background Elements Init
  useEffect(() => {
    const initElements = () => {
      const w = window.innerWidth;
      const h = window.innerHeight;
      const stars = [];
      for (let i = 0; i < 300; i++) {
        stars.push({
          x: Math.random() * w,
          y: Math.random() * h,
          s: Math.random() * 1.5,
          a: Math.random(),
          t: Math.random() * 100,
          speed: 0.01 + Math.random() * 0.02
        });
      }
      backgroundStars.current = stars;
    };

    initElements();
    auroraWaves.current = [
      { offset: 0, speed: 0.0004, color: 'rgba(0, 255, 150, 0.05)' },
      { offset: Math.PI / 2, speed: 0.0003, color: 'rgba(100, 0, 255, 0.04)' },
      { offset: Math.PI, speed: 0.0005, color: 'rgba(0, 200, 255, 0.04)' }
    ];

    window.addEventListener('resize', initElements);
    return () => window.removeEventListener('resize', initElements);
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 55 + 35);

    // Determine Color Palette
    let particleColor: string;
    if (isOffline) {
      particleColor = SUMI_COLORS[Math.floor(Math.random() * SUMI_COLORS.length)];
    } else {
      const finalColors = (activeHoliday && Math.random() > 0.4) ? activeHoliday.specialColors : [color];
      particleColor = finalColors[Math.floor(Math.random() * finalColors.length)];
    }

    const isSpecial = Math.random() > 0.88;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 2.5 + 2.8) * power;

      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: isOffline ? 2.2 : 1.3 + Math.random() * 0.9, // Ink lingers longer
        color: particleColor,
        size: isOffline ? 4 + Math.random() * 6 : 1.6 + Math.random() * 1.6,
        friction: isOffline ? 0.92 : 0.965, // Ink has more drag
        gravity: isOffline ? 0.08 : 0.045, // Ink floats
        trail: [],
        shape: isSpecial ? (Math.random() > 0.5 ? 'star' : 'heart') : 'circle'
      };
      particles.current.push(p);
    }

    // Constellation
    if (!isOffline && Math.random() > 0.93) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 30 * power;
      const rotation = Math.random() * Math.PI * 2;

      constellation.points.forEach(([px, py]) => {
        const cosR = Math.cos(rotation), sinR = Math.sin(rotation);
        const p: Particle = {
          x: x + (px * cosR - py * sinR) * scale,
          y: y + (px * sinR + py * cosR) * scale,
          vx: 0, vy: 0, life: 1, maxLife: 3.5, color: '#FFFFFF', size: 2.5, friction: 0.99, gravity: 0, trail: []
        };
        particles.current.push(p);
      });
    }

    const pool = isOffline ? ANCIENT_QUOTES : (activeHoliday ? activeHoliday.specialQuotes : QUOTES);
    const quote = pool[Math.floor(Math.random() * pool.length)];

    // Elegant text scaling
    setBlessings(prev => [...prev.slice(-2), { text: quote, opacity: 1, y: y - 100, id: Date.now(), scale: 1 }]);
    audioService.playPop(power);
  }, [activeHoliday, isOffline]);

  const triggerGalaxyFall = useCallback((customColor?: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 150; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        const p: Particle = {
          x: x, y: -20, vx: (Math.random() - 0.5) * 0.5, vy: Math.random() * 3 + 2,
          life: 1, maxLife: 5, color: customColor || (isOffline ? '#1a1a1a' : '#FFFFFF'),
          size: 1.2, friction: 0.99, gravity: 0.01, trail: []
        };
        particles.current.push(p);
      }, i * 15);
    }
  }, [isOffline]);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    let color = isOffline ? '#000000' : (activeHoliday ? activeHoliday.specialColors[0] : COLORS[Math.floor(Math.random() * COLORS.length)]);

    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 100,
      y: canvas.height + 20, targetY: y,
      vx: (x - canvas.width / 2) / 70, vy: -13 - power * 2,
      color, power, trail: [], active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    const now = Date.now();
    if (now - lastFireTime.current < 2500) { 
      setCombo(c => {
        const n = c + 1;
        if (n === 5) triggerGalaxyFall(activeHoliday?.specialColors[1]);
        return n;
      });
    } else setCombo(1);
    lastFireTime.current = now;
  }, [triggerGalaxyFall, activeHoliday, isOffline]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;
    ctx.clearRect(0, 0, width, height);

    if (isOffline) {
      // Paper Texture Background for Offline Mode
      ctx.fillStyle = '#fdfbf7';
      ctx.fillRect(0, 0, width, height);
    } else {
      // Deep Space Background
      const bg = ctx.createLinearGradient(0, 0, 0, height);
      bg.addColorStop(0, '#020208');
      bg.addColorStop(1, '#08081a');
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, width, height);

      // Aurora / Nebula Effect
      const now = Date.now();
      ctx.save();
      ctx.globalCompositeOperation = 'screen';
      auroraWaves.current.forEach(w => {
        const g = ctx.createLinearGradient(0, 0, width, 0);
        g.addColorStop(0, 'transparent'); g.addColorStop(0.5, w.color); g.addColorStop(1, 'transparent');
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.moveTo(0, height * 0.4);
        for (let x = 0; x <= width; x += 30) {
          ctx.lineTo(x, height * 0.25 + Math.sin(x * 0.0012 + now * w.speed + w.offset) * 70);
        }
        ctx.lineTo(width, height); ctx.lineTo(0, height);
        ctx.fill();
      });
      ctx.restore();

      // Stars
      backgroundStars.current.forEach(s => {
        s.t += s.speed;
        const o = s.a * (0.2 + Math.sin(s.t) * 0.8);
        ctx.fillStyle = `rgba(255, 255, 255, ${o})`;
        ctx.beginPath(); ctx.arc(s.x, s.y, s.s, 0, Math.PI * 2); ctx.fill();
      });
    }

    // Double Layer Mountains for Parallax
    const drawMountain = (h: number, c: string, p: number) => {
      ctx.fillStyle = c; ctx.beginPath(); ctx.moveTo(0, height);
      for (let x = 0; x <= width; x += 80) {
        ctx.lineTo(x, height - h + Math.sin(x * 0.0008 * p) * 35);
      }
      ctx.lineTo(width, height); ctx.fill();
    };

    if (isOffline) {
      drawMountain(140, '#e5e0d4', 0.6); // Far mountain ink
      drawMountain(90, '#d8d3c5', 1.3); // Near mountain ink
    } else {
      drawMountain(160, '#010107', 0.4); // Far mountain
      drawMountain(110, '#03030d', 1.2); // Near mountain
    }

    // Projectiles
    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx; p.y += p.vy; p.vy += 0.16;
      p.trail.push({ x: p.x, y: p.y }); if (p.trail.length > 25) p.trail.shift();
      ctx.beginPath(); ctx.strokeStyle = p.color; ctx.lineWidth = isOffline ? 4 : 2; ctx.lineCap = 'round';
      p.trail.forEach((pos, i) => { ctx.globalAlpha = i/p.trail.length; if(i===0) ctx.moveTo(pos.x, pos.y); else ctx.lineTo(pos.x, pos.y); });
      ctx.stroke(); ctx.globalAlpha = 1;
      if (p.vy >= 0 || p.y <= p.targetY) { p.active = false; createParticles(p.x, p.y, p.color, p.power); }
    });

    // Particles
    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction; p.vy *= p.friction; p.vy += p.gravity; p.x += p.vx; p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);
      if (p.life > 0) {
        ctx.fillStyle = p.color; ctx.globalAlpha = isOffline ? p.life * 0.8 : Math.pow(p.life, 2);
        const s = Math.max(0.1, p.size * (isOffline ? p.life : p.life * 1.5));
        ctx.beginPath(); ctx.arc(p.x, p.y, s, 0, Math.PI * 2); ctx.fill();
      }
    });
    ctx.globalAlpha = 1;
    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles, isOffline]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    window.addEventListener('resize', resize); resize();
    requestRef.current = requestAnimationFrame(() => update(ctx));
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); window.removeEventListener('resize', resize); };
  }, [update]);

  useEffect(() => {
    let t: number;
    if (charging) t = window.setInterval(() => setChargeLevel(p => Math.min(p + 0.045, 3)), 30);
    else setChargeLevel(0);
    return () => clearInterval(t);
  }, [charging]);

  const onPointerDown = () => setCharging(true);
  const onPointerUp = (e: React.PointerEvent) => {
    if (!charging) return;
    setCharging(false);
    launchFirework(e.clientX, e.clientY, chargeLevel);
  };

  useEffect(() => {
    const t = setInterval(() => {
      setBlessings(prev => prev.map(b => ({ ...b, y: b.y - (isOffline ? 0.3 : 0.5), opacity: b.opacity - 0.0035 }))
        .filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(t);
  }, [isOffline]);

  return (
    <div 
      className={`relative w-full h-screen overflow-hidden transition-all duration-1000 ${isOffline ? 'bg-[#fdfbf7]' : 'bg-[#020205]'}`}
      onPointerDown={onPointerDown}
      onPointerUp={onPointerUp}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      {/* Holiday Splash Screen */}
      {showHolidaySplash && !isOffline && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-[#400]/90 pointer-events-none">
          <div className="text-center">
            <h2 className="text-[#D4AF37] font-poetic text-8xl animate-poetic-entry">春节快乐</h2>
          </div>
        </div>
      )}

      {/* Minimalist Header */}
      <div className="absolute top-16 left-0 right-0 pointer-events-none flex flex-col items-center select-none z-10">
        <h1 className={`text-2xl font-serif-elegant tracking-[0.5em] opacity-40 mb-2 transition-colors duration-1000 ${isOffline ? 'text-black' : 'text-white'}`}>
          {isOffline ? '墨 · 染' : '星 愿 · 夜 穹'}
        </h1>
        <div className={`h-[1px] w-14 transition-colors duration-1000 ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}></div>
      </div>

      {/* Elegant Charging Line */}
      <div className={`absolute bottom-20 left-1/2 -translate-x-1/2 w-44 flex flex-col items-center gap-2 z-20 transition-opacity duration-300 ${charging ? 'opacity-100' : 'opacity-0'}`}>
        <div className={`h-[1px] w-full relative overflow-hidden ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}>
          <div className={`h-full absolute left-0 transition-all duration-75 ${isOffline ? 'bg-black' : 'bg-white'}`} style={{ width: `${(chargeLevel/3)*100}%` }} />
        </div>
        <span className={`text-[8px] tracking-[0.4em] font-serif-elegant uppercase ${isOffline ? 'text-black/40' : 'text-white/40'}`}>Gilding The Night</span>
      </div>

      {/* Subtle Combo Display */}
      {combo > 1 && (
        <div className="absolute top-40 left-1/2 -translate-x-1/2 z-10">
          <span className={`font-serif-elegant text-xs italic tracking-widest ${isOffline ? 'text-[#800]' : 'text-[#D4AF37]'}`}>{combo}x Harmony</span>
        </div>
      )}

      {/* Floating Blessings */}
      {blessings.map(b => (
        <div key={b.id} className="absolute left-1/2 -translate-x-1/2 pointer-events-none font-serif-elegant text-2xl whitespace-nowrap z-10"
          style={{ top: `${b.y}px`, opacity: b.opacity, color: isOffline ? '#000' : '#fff', letterSpacing: '0.5em' }}>
          {b.text}
        </div>
      ))}

      {/* Footer Status */}
      <div className={`absolute bottom-8 right-10 text-[8px] tracking-[0.3em] font-serif-elegant pointer-events-none z-10 uppercase ${isOffline ? 'text-black/20' : 'text-white/20'}`}>
        {isOffline ? 'Paper & Ink' : (activeHoliday ? `Event: ${activeHoliday.name}` : 'Eternal Starlight')}
      </div>
    </div>
  );
};

