import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point, HolidayConfig } from './types';
import { QUOTES, ANCIENT_QUOTES, COLORS, SUMI_COLORS, CONSTELLATIONS, HOLIDAYS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const [activeHoliday, setActiveHoliday] = useState<HolidayConfig | null>(null);
  const [showHolidaySplash, setShowHolidaySplash] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  const lastFireTime = useRef(0);
  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number, speed: number}[]>([]);
  const auroraWaves = useRef<{offset: number, speed: number, color: string}[]>([]);
  const requestRef = useRef<number>();

  // Connectivity & Holiday Logic
  useEffect(() => {
    const syncOnline = () => setIsOffline(false);
    const syncOffline = () => setIsOffline(true);
    window.addEventListener('online', syncOnline);
    window.addEventListener('offline', syncOffline);

    const now = new Date();
    const holiday = HOLIDAYS.find(h => h.match(now));
    if (holiday) {
      setActiveHoliday(holiday);
      const storageKey = `holiday_splash_${holiday.id}_${now.getFullYear()}`;
      if (holiday.firstLaunchEffect && !localStorage.getItem(storageKey)) {
        setShowHolidaySplash(true);
        localStorage.setItem(storageKey, 'true');
        setTimeout(() => setShowHolidaySplash(false), 5000);
      }
    }

    return () => {
      window.removeEventListener('online', syncOnline);
      window.removeEventListener('offline', syncOffline);
    };
  }, []);

  // Init Background Elements
  useEffect(() => {
    const initElements = () => {
      const w = window.innerWidth;
      const h = window.innerHeight;
      const stars = [];
      for (let i = 0; i < 250; i++) {
        stars.push({
          x: Math.random() * w,
          y: Math.random() * h * 0.8,
          s: Math.random() * 1.5,
          a: Math.random(),
          t: Math.random() * 100,
          speed: 0.005 + Math.random() * 0.015
        });
      }
      backgroundStars.current = stars;
    };

    initElements();

    // Setup Aurora Waves
    auroraWaves.current = [
      { offset: 0, speed: 0.0004, color: 'rgba(0, 255, 150, 0.03)' },
      { offset: Math.PI / 2, speed: 0.0003, color: 'rgba(100, 0, 255, 0.02)' },
      { offset: Math.PI, speed: 0.0005, color: 'rgba(0, 200, 255, 0.03)' }
    ];

    window.addEventListener('resize', initElements);
    return () => window.removeEventListener('resize', initElements);
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 55 + 35);

    // Color Selection Logic
    let particleColor: string;
    if (isOffline) {
      particleColor = SUMI_COLORS[Math.floor(Math.random() * SUMI_COLORS.length)];
    } else {
      const colors = (activeHoliday && Math.random() > 0.4) ? activeHoliday.specialColors : [color];
      particleColor = colors[Math.floor(Math.random() * colors.length)];
    }

    const isSpecial = Math.random() > 0.88;
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const velocityVariance = 0.8 + Math.random() * 0.4;
      const speed = (Math.random() * 4 + 4) * power * velocityVariance;

      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: isOffline ? 2.2 : 0.9 + Math.random() * 0.6,
        color: particleColor,
        size: isOffline ? 4 + Math.random() * 5 : 2 + Math.random() * 2,
        friction: isOffline ? 0.92 : 0.96, 
        gravity: isOffline ? 0.08 : 0.25,
        trail: [],
        shape: isSpecial ? (Math.random() > 0.5 ? 'star' : 'heart') : 'circle'
      };
      particles.current.push(p);
    }

    // Sparkles
    if (!isOffline) {
        const subCount = count * 0.6;
        for (let i = 0; i < subCount; i++) {
          const angle = Math.random() * Math.PI * 2;
          const speed = (Math.random() * 3 + 2) * power;
          const p: Particle = {
            x, y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed,
            life: 1, maxLife: 1.2, color: '#FFFFFF', size: 1.5,
            friction: 0.94, gravity: 0.15, trail: []
          };
          particles.current.push(p);
        }
    }

    // Smoke/Cloud
    for (let i = 0; i < 40; i++) {
      const angle = Math.random() * Math.PI * 2;
      const speed = Math.random() * 2 * power;
      const p: Particle = {
        x: x + (Math.random() - 0.5) * 20, y: y + (Math.random() - 0.5) * 20,
        vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed,
        life: 1, maxLife: 2.0, color: isOffline ? 'rgba(0,0,0,0.1)' : 'rgba(255,255,255,0.4)',
        size: isOffline ? 2 : 0.8, friction: 0.92, gravity: 0.05, trail: [],
        wobbleSpeed: 0.05, wobbleTheta: Math.random() * Math.PI * 2
      };
      particles.current.push(p);
    }

    // Constellation
    if (!isOffline && Math.random() > 0.93) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 30 * power;
      const rotation = Math.random() * Math.PI * 2;

      constellation.points.forEach(([px, py]) => {
        const cosR = Math.cos(rotation), sinR = Math.sin(rotation);
        const p: Particle = {
          x: x + (px * cosR - py * sinR) * scale,
          y: y + (px * sinR + py * cosR) * scale,
          vx: 0, vy: 0, life: 1, maxLife: 3.5, color: '#ADD8E6', size: 3, friction: 0.99, gravity: 0, trail: []
        };
        particles.current.push(p);
      });
    }

    const pool = isOffline ? ANCIENT_QUOTES : (activeHoliday ? activeHoliday.specialQuotes : QUOTES);
    const quote = pool[Math.floor(Math.random() * pool.length)];
    setBlessings(prev => [...prev.slice(-2), { text: quote, opacity: 1, y: y - 80, id: Date.now(), scale: 1 }]);

    audioService.playPop(power);
  }, [isOffline, activeHoliday]);

  const triggerGalaxyFall = useCallback((customColor?: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    for (let i = 0; i < 150; i++) {
      setTimeout(() => {
        const x = Math.random() * canvas.width;
        const p: Particle = {
          x: x, y: -20, vx: (Math.random() - 0.5) * 0.5, vy: Math.random() * 3 + 2,
          life: 1, maxLife: 5, color: customColor || (isOffline ? '#1a1a1a' : '#E0F0FF'),
          size: 1.5, friction: 0.99, gravity: 0.01, trail: [], wobbleSpeed: 0.03, wobbleTheta: Math.random() * Math.PI * 2
        };
        particles.current.push(p);
      }, i * 15);
    }
  }, [isOffline]);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    let color = isOffline ? '#000000' : (activeHoliday ? activeHoliday.specialColors[0] : COLORS[Math.floor(Math.random() * COLORS.length)]);

    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 100,
      y: canvas.height + 20, targetY: y,
      vx: (x - canvas.width / 2) / 60, vy: -16 - power * 4,
      color, power, trail: [], active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    const now = Date.now();
    if (now - lastFireTime.current < 2500) { 
      setCombo(c => {
        const n = c + 1;
        if (n === 5) triggerGalaxyFall(activeHoliday?.specialColors[1]);
        return n;
      });
    } else setCombo(1);
    lastFireTime.current = now;
  }, [triggerGalaxyFall, isOffline, activeHoliday]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;

    // Dynamic Background
    if (isOffline) {
      ctx.fillStyle = '#fdfbf7'; // Cream paper
      ctx.fillRect(0, 0, width, height);
    } else {
      const grad = ctx.createLinearGradient(0, 0, 0, height);
      grad.addColorStop(0, '#020205'); // Deep Black
      grad.addColorStop(1, '#080815'); // Midnight Blue
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, width, height);

      // Aurora
      const now = Date.now();
      ctx.save();
      ctx.globalCompositeOperation = 'screen';
      auroraWaves.current.forEach(w => {
        const g = ctx.createLinearGradient(0, 0, width, 0);
        g.addColorStop(0, 'transparent'); g.addColorStop(0.5, w.color); g.addColorStop(1, 'transparent');
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.moveTo(0, height * 0.4);
        for (let x = 0; x <= width; x += 30) {
          ctx.lineTo(x, height * 0.25 + Math.sin(x * 0.0012 + now * w.speed + w.offset) * 70);
        }
        ctx.lineTo(width, height); ctx.lineTo(0, height);
        ctx.fill();
      });
      ctx.restore();

      // Stars
      backgroundStars.current.forEach(s => {
        s.t += s.speed;
        const o = s.a * (0.2 + Math.sin(s.t) * 0.8);
        ctx.fillStyle = `rgba(255, 255, 255, ${o})`;
        ctx.beginPath(); ctx.arc(s.x, s.y, s.s, 0, Math.PI * 2); ctx.fill();
      });
    }

    // Parallax Mountains
    const drawMountain = (h: number, c: string, p: number) => {
        ctx.fillStyle = c; ctx.beginPath(); ctx.moveTo(0, height);
        for (let x = 0; x <= width; x += 80) {
          ctx.lineTo(x, height - h + Math.sin(x * 0.0008 * p) * 35);
        }
        ctx.lineTo(width, height); ctx.fill();
    };

    if (isOffline) {
        drawMountain(140, '#e5e0d4', 0.6); 
        drawMountain(90, '#d8d3c5', 1.3); 
    } else {
        drawMountain(160, '#010107', 0.4); 
        drawMountain(110, '#03030d', 1.2); 
    }

    // Draw Projectiles
    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx; p.y += p.vy; p.vy += 0.25;
      p.trail.push({ x: p.x, y: p.y }); if (p.trail.length > 20) p.trail.shift();

      ctx.beginPath(); ctx.strokeStyle = p.color; ctx.lineWidth = isOffline ? 3 : 2; ctx.lineCap = 'round';
      p.trail.forEach((pos, idx) => {
        ctx.globalAlpha = idx / p.trail.length;
        if (idx === 0) ctx.moveTo(pos.x, pos.y); else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke(); ctx.globalAlpha = 1;

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    // Draw Particles
    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction; p.vy *= p.friction; p.vy += p.gravity;
      if (p.wobbleSpeed !== undefined && p.wobbleTheta !== undefined) {
        p.wobbleTheta += p.wobbleSpeed; p.x += Math.sin(p.wobbleTheta) * 0.3;
      }
      p.x += p.vx; p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        const alpha = isOffline ? p.life * 0.8 : Math.pow(p.life, 2);
        const twinkle = (p.shape === 'star' && !isOffline) ? 0.7 + Math.random() * 0.3 : 1;
        ctx.globalAlpha = alpha * twinkle;

        if (p.shape === 'star') {
            const r = p.size; ctx.beginPath();
            for(let i=0; i<5; i++) {
              const a = (Math.PI*2/5)*i - Math.PI/2;
              const x = p.x + Math.cos(a)*r*1.5; const y = p.y + Math.sin(a)*r*1.5;
              if(i===0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
              const a2 = a + Math.PI/5;
              ctx.lineTo(p.x + Math.cos(a2)*r*0.6, p.y + Math.sin(a2)*r*0.6);
            }
            ctx.closePath(); ctx.fill();
        } else {
            const s = Math.max(0.1, p.size * (isOffline ? p.life : p.life * 1.5));
            ctx.beginPath(); ctx.arc(p.x, p.y, s, 0, Math.PI * 2); ctx.fill();
        }
      }
    });
    ctx.globalAlpha = 1;

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles, isOffline]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    window.addEventListener('resize', resize); resize();
    requestRef.current = requestAnimationFrame(() => update(ctx));
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); window.removeEventListener('resize', resize); };
  }, [update]);

  useEffect(() => {
    let timer: number;
    if (charging) timer = window.setInterval(() => setChargeLevel(p => Math.min(p + 0.045, 3)), 30);
    else setChargeLevel(0);
    return () => clearInterval(timer);
  }, [charging]);

  const onPointerDown = () => setCharging(true);
  const onPointerUp = (e: React.PointerEvent) => {
    if (!charging) return;
    setCharging(false);
    launchFirework(e.clientX, e.clientY, chargeLevel);
  };

  useEffect(() => {
    const t = setInterval(() => {
      setBlessings(prev => prev.map(b => ({ ...b, y: b.y - (isOffline ? 0.3 : 0.5), opacity: b.opacity - 0.0035 }))
        .filter(b => b.opacity > 0));
    }, 16);
    return () => clearInterval(t);
  }, [isOffline]);

  return (
    <div 
      className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 ${isOffline ? 'bg-[#fdfbf7]' : 'bg-[#020205]'}`}
      onPointerDown={onPointerDown}
      onPointerUp={onPointerUp}
    >
      <canvas ref={canvasRef} className="absolute inset-0 cursor-crosshair" />

      {/* Holiday Splash */}
      {showHolidaySplash && !isOffline && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-[#200]/90 pointer-events-none">
          <div className="text-center">
             <h2 className="text-[#D4AF37] font-poetic text-8xl animate-poetic-entry">{activeHoliday?.name}快乐</h2>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="absolute top-12 left-0 right-0 pointer-events-none flex flex-col items-center select-none z-10">
        <h1 className={`text-2xl font-serif-elegant font-light opacity-50 mb-3 transition-colors duration-1000 ${isOffline ? 'text-black' : 'text-white'}`}>
          {isOffline ? '墨 · 染' : '星 愿 · 夜 穹'}
        </h1>
        <div className={`h-[1px] w-12 transition-colors duration-1000 ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}></div>
      </div>

      {/* Hairline Progress Bar */}
      <div className={`absolute bottom-20 left-1/2 -translate-x-1/2 w-48 flex flex-col items-center gap-2 z-20 transition-opacity duration-300 ${charging ? 'opacity-100' : 'opacity-0'}`}>
        <div className={`h-[1px] w-full relative overflow-hidden ${isOffline ? 'bg-black/10' : 'bg-white/10'}`}>
          <div className={`h-full absolute left-0 transition-all duration-75 ${isOffline ? 'bg-black' : 'bg-white'}`} style={{ width: `${(chargeLevel/3)*100}%` }} />
        </div>
        <span className={`text-[9px] tracking-[0.3em] font-serif-elegant uppercase ${isOffline ? 'text-black/40' : 'text-white/40'}`}>Gilding The Night</span>
      </div>

      {/* Elegant Combo */}
      {combo > 1 && (
        <div className="absolute top-32 left-1/2 -translate-x-1/2 z-10 transition-all duration-500">
          <span className={`font-serif-elegant text-sm italic tracking-widest ${isOffline ? 'text-[#800]' : 'text-[#D4AF37]'}`}>{combo}x Harmony</span>
        </div>
      )}

      {/* Blessings */}
      {blessings.map(b => (
        <div key={b.id} className={`absolute left-1/2 -translate-x-1/2 pointer-events-none font-serif-elegant text-xl whitespace-nowrap z-10 ${isOffline ? 'text-black' : 'text-white'}`}
          style={{ top: `${b.y}px`, opacity: b.opacity, textShadow: isOffline ? 'none' : '0 0 10px rgba(255,255,255,0.3)' }}>
          {b.text}
        </div>
      ))}

      {/* Footer */}
      <div className={`absolute bottom-6 right-8 text-[9px] tracking-[0.2em] font-serif-elegant pointer-events-none z-10 uppercase ${isOffline ? 'text-black/20' : 'text-white/20'}`}>
        {isOffline ? 'Paper & Ink' : (activeHoliday ? `Event: ${activeHoliday.name}` : 'Eternal Starlight')}
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Particle, FireworkProjectile, Blessing, Point } from './types';
import { QUOTES, COLORS, SUMI_COLORS, CONSTELLATIONS } from './constants';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [combo, setCombo] = useState(0);
  const [isOffline, setIsOffline] = useState(false);

  const lastFireTime = useRef(0);
  const lastTitleClickTime = useRef(0);
  const particles = useRef<Particle[]>([]);
  const projectiles = useRef<FireworkProjectile[]>([]);
  const backgroundStars = useRef<{x: number, y: number, s: number, a: number, t: number, speed: number}[]>([]);
  const requestRef = useRef<number>();

  // 初始化背景元素
  useEffect(() => {
    const stars = [];
    for (let i = 0; i < 250; i++) {
      stars.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight,
        s: Math.random() * 1.5,
        a: Math.random(),
        t: Math.random() * 100,
        speed: 0.01 + Math.random() * 0.03
      });
    }
    backgroundStars.current = stars;
  }, []);

  const createParticles = useCallback((x: number, y: number, color: string, power: number) => {
    const count = Math.floor(power * 50 + 40);
    const particlePool = isOffline ? SUMI_COLORS : COLORS;
    const finalColor = isOffline ? particlePool[Math.floor(Math.random() * particlePool.length)] : color;

    // 核心爆裂
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 / count) * i;
      const speed = (Math.random() * 3 + 3) * power;

      const p: Particle = {
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1,
        maxLife: isOffline ? 2.5 : 1.2 + Math.random() * 0.8,
        color: finalColor,
        size: isOffline ? 4 + Math.random() * 4 : 2 + Math.random() * 1.5,
        friction: isOffline ? 0.93 : 0.96,
        gravity: isOffline ? 0.08 : 0.22,
        trail: []
      };
      particles.current.push(p);
    }

    // 次级尘埃
    if (power > 1.5 && !isOffline) {
      for (let i = 0; i < 30; i++) {
        const angle = Math.random() * Math.PI * 2;
        const speed = Math.random() * 2 * power;
        particles.current.push({
          x, y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed,
          life: 1, maxLife: 2.0, color: 'rgba(255,255,255,0.4)', size: 0.8,
          friction: 0.92, gravity: 0.05, trail: [], wobbleSpeed: 0.05, wobbleTheta: Math.random() * Math.PI * 2
        });
      }
    }

    // 随机星群
    if (Math.random() > 0.9 && !isOffline) {
      const constellation = CONSTELLATIONS[Math.floor(Math.random() * CONSTELLATIONS.length)];
      const scale = 25 * power;
      const rotation = Math.random() * Math.PI * 2;
      const cosR = Math.cos(rotation), sinR = Math.sin(rotation);

      constellation.points.forEach(([px, py]) => {
        particles.current.push({
          x: x + (px * cosR - py * sinR) * scale,
          y: y + (px * sinR + py * cosR) * scale,
          vx: 0, vy: 0, life: 1, maxLife: 4.0, color: '#FFFFFF', size: 2.5, friction: 0.99, gravity: 0, trail: []
        });
      });
    }

    const quote = QUOTES[Math.floor(Math.random() * QUOTES.length)];
    setBlessings(prev => [...prev.slice(-2), { text: quote, opacity: 1, y: y - 80, id: Date.now() }]);
    audioService.playPop(power);
  }, [isOffline]);

  const launchFirework = useCallback((x: number, y: number, power: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const color = isOffline ? '#000' : COLORS[Math.floor(Math.random() * COLORS.length)];
    const projectile: FireworkProjectile = {
      x: canvas.width / 2 + (Math.random() - 0.5) * 40,
      y: canvas.height + 20,
      targetY: y,
      vx: (x - canvas.width / 2) / 65,
      vy: -14 - power * 3,
      color, power, trail: [], active: true
    };
    projectiles.current.push(projectile);
    audioService.playLaunch();

    const now = Date.now();
    if (now - lastFireTime.current < 2500) {
      setCombo(c => c + 1);
    } else {
      setCombo(1);
    }
    lastFireTime.current = now;
  }, [isOffline]);

  const update = useCallback((ctx: CanvasRenderingContext2D) => {
    const { width, height } = ctx.canvas;

    // 背景绘制
    if (isOffline) {
      ctx.fillStyle = '#f5f0e6'; // 宣纸色
      ctx.fillRect(0, 0, width, height);
    } else {
      const grad = ctx.createLinearGradient(0, 0, 0, height);
      grad.addColorStop(0, '#020205'); // 极深蓝黑
      grad.addColorStop(1, '#08081a');
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, width, height);

      // 绘制流动的星空
      backgroundStars.current.forEach(star => {
        star.t += star.speed;
        const alpha = star.a * (0.3 + Math.sin(star.t) * 0.7);
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.s, 0, Math.PI * 2);
        ctx.fill();
      });
    }

    // 绘制烟火轨迹
    projectiles.current = projectiles.current.filter(p => p.active);
    projectiles.current.forEach(p => {
      p.x += p.vx; p.y += p.vy; p.vy += 0.22;
      p.trail.push({ x: p.x, y: p.y });
      if (p.trail.length > 20) p.trail.shift();

      ctx.beginPath();
      ctx.strokeStyle = p.color;
      ctx.lineWidth = isOffline ? 4 : 1.5;
      ctx.lineCap = 'round';
      p.trail.forEach((pos, idx) => {
        ctx.globalAlpha = idx / p.trail.length;
        if (idx === 0) ctx.moveTo(pos.x, pos.y);
        else ctx.lineTo(pos.x, pos.y);
      });
      ctx.stroke();
      ctx.globalAlpha = 1;

      if (p.vy >= 0 || p.y <= p.targetY) {
        p.active = false;
        createParticles(p.x, p.y, p.color, p.power);
      }
    });

    // 绘制粒子
    particles.current = particles.current.filter(p => p.life > 0);
    particles.current.forEach(p => {
      p.vx *= p.friction; p.vy *= p.friction; p.vy += p.gravity;
      if (p.wobbleSpeed) {
        p.wobbleTheta! += p.wobbleSpeed;
        p.x += Math.sin(p.wobbleTheta!) * 0.3;
      }
      p.x += p.vx; p.y += p.vy;
      p.life -= 1 / (60 * p.maxLife);

      if (p.life > 0) {
        ctx.fillStyle = p.color;
        const alpha = isOffline ? p.life * 0.8 : Math.pow(p.life, 2);
        ctx.globalAlpha = alpha;

        ctx.beginPath();
        const size = Math.max(0.1, p.size * (isOffline ? p.life : p.life * 1.5));
        ctx.arc(p.x, p.y, size, 0, Math.PI * 2);
        ctx.fill();
      }
    });
    ctx.globalAlpha = 1;

    requestRef.current = requestAnimationFrame(() => update(ctx));
  }, [createParticles, isOffline]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    window.addEventListener('resize', resize);
    resize();
    requestRef.current = requestAnimationFrame(() => update(ctx));
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', resize);
    };
  }, [update]);

  // 蓄力逻辑
  useEffect(() => {
    let timer: number;
    if (charging) {
      timer = window.setInterval(() => setChargeLevel(p => Math.min(p + 0.04, 3)), 30);
    }
    return () => clearInterval(timer);
  }, [charging]);

  const handleTitleClick = () => {
    const now = Date.now();
    if (now - lastTitleClickTime.current < 350) {
      setIsOffline(!isOffline);
    }
    lastTitleClickTime.current = now;
  };

  const onPointerDown = () => setCharging(true);
  const onPointerUp = (e: React.PointerEvent) => {
    if (!charging) return;
    setCharging(false);
    launchFirework(e.clientX, e.clientY, chargeLevel);
    setChargeLevel(0);
  };

  useEffect(() => {
